 12→fn document_absolute_path_from_media_ref(media_ref: &str) -> String {
 13→    if Path::new(media_ref).is_absolute() {
 14→        return media_ref.to_string();
 15→    }
 16→
 17→    moltis_config::data_dir()
 18→        .join("sessions")
 19→        .join(media_ref)
 20→        .to_string_lossy()
 21→        .to_string()
 22→}
