237→/// Convert persisted JSON messages (from session store) to typed `ChatMessage`s.
238→///
239→/// Skips messages that don't have a valid `role` field, logging a warning.
240→/// Metadata fields (`created_at`, `model`, `provider`, `inputTokens`,
241→/// `outputTokens`, `channel`) are silently dropped — they only exist in
242→/// the persisted JSON, not in `ChatMessage`.
243→pub fn values_to_chat_messages(values: &[serde_json::Value]) -> Vec<ChatMessage> {
244→    let mut messages = Vec::with_capacity(values.len());
245→    // Track tool_call IDs emitted by assistant messages so we only include
246→    // tool/tool_result messages that have a matching assistant tool_call.
247→    // Orphan tool results (e.g. from explicit /sh commands) would cause
248→    // provider API errors.
249→    let mut pending_tool_call_ids: std::collections::HashSet<String> =
250→        std::collections::HashSet::new();
251→    for (i, val) in values.iter().enumerate() {
252→        let Some(role) = val["role"].as_str() else {
253→            tracing::warn!(index = i, "skipping message with missing/invalid role");
254→            continue;
255→        };
256→        match role {
257→            "system" => {
258→                let content = val["content"].as_str().unwrap_or("").to_string();
259→                messages.push(ChatMessage::system(content));
260→            },
261→            "user" => {
262→                // Extract sender name from persisted channel metadata.
263→                let sender_name = val
264→                    .get("channel")
265→                    .and_then(|ch| {
266→                        ch["sender_name"]
267→                            .as_str()
268→                            .or_else(|| ch["username"].as_str())
269→                    })
270→                    .map(|s| s.to_string());
271→
272→                let document_context = val["documents"].as_array().and_then(|documents| {
273→                    let mut sections = Vec::new();
274→                    for document in documents {
275→                        let Some(display_name) = document["display_name"].as_str() else {
276→                            continue;
277→                        };
278→                        let Some(mime_type) = document["mime_type"].as_str() else {
279→                            continue;
280→                        };
281→                        let Some(media_ref) = document["media_ref"].as_str() else {
282→                            continue;
283→                        };
284→                        let absolute_path = document_absolute_path_from_media_ref(media_ref);
285→                        sections.push(format!(
286→                            "filename: {display_name}\nmime_type: {mime_type}\nlocal_path: {absolute_path}\nmedia_ref: {media_ref}"
287→                        ));
288→                    }
289→                    if sections.is_empty() {
290→                        None
291→                    } else {
292→                        let mut rendered = vec!["[Inbound documents available]".to_string()];
293→                        rendered.extend(sections);
294→                        Some(rendered.join("\n\n"))
295→                    }
296→                });
297→
298→                // Content can be a string or an array (multimodal).
299→                if let Some(text) = val["content"].as_str() {
300→                    let content = if let Some(ref document_context) = document_context {
301→                        if text.trim().is_empty() {
302→                            document_context.clone()
303→                        } else {
304→                            format!("{text}\n\n{document_context}")
305→                        }
306→                    } else {
307→                        text.to_string()
308→                    };
309→                    messages.push(ChatMessage::User {
310→                        content: UserContent::Text(content),
311→                        name: sender_name,
312→                    });
313→                } else if let Some(arr) = val["content"].as_array() {
314→                    let mut parts: Vec<ContentPart> = arr
315→                        .iter()
316→                        .filter_map(|block| {
317→                            let block_type = block["type"].as_str()?;
318→                            match block_type {
319→                                "text" => {
320→                                    let text = block["text"].as_str()?.to_string();
321→                                    Some(ContentPart::Text(text))
322→                                },
323→                                "image_url" => {
324→                                    let url = block["image_url"]["url"].as_str()?;
325→                                    let (media_type, data) = parse_data_uri(url)?;
326→                                    Some(ContentPart::Image {
327→                                        media_type: media_type.to_string(),
328→                                        data: data.to_string(),
329→                                    })
330→                                },
331→                                _ => None,
332→                            }
333→                        })
334→                        .collect();
335→                    if let Some(document_context) = document_context {
336→                        if let Some(ContentPart::Text(text)) = parts
337→                            .iter_mut()
338→                            .find(|part| matches!(part, ContentPart::Text(_)))
339→                        {
340→                            if !text.trim().is_empty() {
341→                                text.push_str("\n\n");
342→                            }
343→                            text.push_str(&document_context);
344→                        } else {
345→                            parts.insert(0, ContentPart::Text(document_context));
346→                        }
347→                    }
348→                    messages.push(ChatMessage::User {
349→                        content: UserContent::Multimodal(parts),
350→                        name: sender_name,
351→                    });
352→                } else {
353→                    messages.push(ChatMessage::User {
354→                        content: UserContent::Text(document_context.unwrap_or_default()),
355→                        name: sender_name,
356→                    });
357→                }
358→            },
359→            "assistant" => {
360→                let content = val["content"].as_str().map(|s| s.to_string());
361→                let tool_calls: Vec<ToolCall> = val["tool_calls"]
362→                    .as_array()
363→                    .map(|tcs| {
364→                        tcs.iter()
365→                            .filter_map(|tc| {
366→                                let id = tc["id"].as_str()?.to_string();
367→                                let name = tc["function"]["name"].as_str()?.to_string();
368→                                let arguments =
369→                                    decode_tool_call_arguments(tc["function"].get("arguments"));
370→                                Some(ToolCall {
371→                                    id,
372→                                    name,
373→                                    arguments,
374→                                })
375→                            })
376→                            .collect()
377→                    })
378→                    .unwrap_or_default();
379→                for tc in &tool_calls {
380→                    pending_tool_call_ids.insert(tc.id.clone());
381→                }
382→                messages.push(ChatMessage::Assistant {
383→                    content,
384→                    tool_calls,
385→                });
386→            },
387→            "tool" => {
388→                let tool_call_id = val["tool_call_id"].as_str().unwrap_or("").to_string();
389→                if !pending_tool_call_ids.remove(&tool_call_id) {
390→                    tracing::debug!(tool_call_id, "skipping orphan tool message");
391→                    continue;
392→                }
393→                let content = if let Some(s) = val["content"].as_str() {
394→                    s.to_string()
395→                } else {
396→                    val["content"].to_string()
397→                };
398→                messages.push(ChatMessage::tool(tool_call_id, content));
399→            },
400→            // tool_result entries are persisted tool execution output; convert
401→            // them to standard tool messages so the LLM sees its own results.
402→            "tool_result" => {
403→                let tool_call_id = val["tool_call_id"].as_str().unwrap_or("").to_string();
404→                if !pending_tool_call_ids.remove(&tool_call_id) {
405→                    tracing::debug!(tool_call_id, "skipping orphan tool_result message");
406→                    continue;
407→                }
408→                let content = if let Some(err) = val["error"].as_str() {
409→                    format!("Error: {err}")
410→                } else if let Some(result) = val.get("result") {
411→                    if let Some(s) = result.as_str() {
412→                        s.to_string()
413→                    } else {
414→                        result.to_string()
415→                    }
416→                } else {
417→                    String::new()
418→                };
419→                messages.push(ChatMessage::tool(tool_call_id, content));
420→            },
421→            // notice entries are UI-only informational messages.
422→            "notice" => continue,
423→            other => {
424→                tracing::warn!(
425→                    index = i,
426→                    role = other,
427→                    "skipping message with unknown role"
428→                );
429→            },
430→        }
431→    }
432→    messages
433→}
