437→/// Events emitted during streaming LLM completion.
438→#[derive(Debug, Clone)]
439→pub enum StreamEvent {
440→    /// Text content delta.
441→    Delta(String),
442→    /// Raw provider event payload (for debugging API responses).
443→    ProviderRaw(serde_json::Value),
444→    /// Reasoning/planning text delta (not user-visible final answer text).
445→    ReasoningDelta(String),
446→    /// A tool call has started (content_block_start with tool_use).
447→    ToolCallStart {
448→        /// Tool call ID from the provider.
449→        id: String,
450→        /// Tool name being called.
451→        name: String,
452→        /// Index of this tool call in the response (0-based).
453→        index: usize,
454→    },
455→    /// Streaming delta for tool call arguments (JSON fragment).
456→    ToolCallArgumentsDelta {
457→        /// Index of the tool call this delta belongs to.
458→        index: usize,
459→        /// JSON fragment to append to the arguments.
460→        delta: String,
461→    },
462→    /// A tool call's arguments are complete.
463→    ToolCallComplete {
464→        /// Index of the completed tool call.
465→        index: usize,
466→    },
467→    /// Stream completed successfully.
468→    Done(Usage),
469→    /// An error occurred.
470→    Error(String),
471→}
