473→/// LLM provider trait (Anthropic, OpenAI, Google, etc.).
474→#[async_trait]
475→pub trait LlmProvider: Send + Sync {
476→    fn name(&self) -> &str;
477→
478→    /// Model identifier (e.g. "claude-sonnet-4-20250514", "gpt-4o").
479→    fn id(&self) -> &str;
480→
481→    async fn complete(
482→        &self,
483→        messages: &[ChatMessage],
484→        tools: &[serde_json::Value],
485→    ) -> anyhow::Result<CompletionResponse>;
486→
487→    /// Whether this provider supports tool/function calling.
488→    /// Defaults to false; providers that handle the `tools` parameter
489→    /// in `complete()` should override this to return true.
490→    fn supports_tools(&self) -> bool {
491→        false
492→    }
493→
494→    /// Context window size in tokens for this model.
495→    /// Used to detect when conversation approaches the limit and trigger auto-compact.
496→    fn context_window(&self) -> u32 {
497→        200_000
498→    }
