 39→/// Run the agent loop: send messages to the LLM, execute tool calls, repeat.
 40→///
 41→/// If `history` is provided, those messages are inserted between the system
 42→/// prompt and the current user message, giving the LLM conversational context.
 43→pub async fn run_agent_loop(
 44→    provider: Arc<dyn LlmProvider>,
 45→    tools: &ToolRegistry,
 46→    system_prompt: &str,
 47→    user_content: &UserContent,
 48→    on_event: Option<&OnEvent>,
 49→    history: Option<Vec<ChatMessage>>,
 50→) -> Result<AgentRunResult, AgentRunError> {
 51→    run_agent_loop_with_context(
 52→        provider,
 53→        tools,
 54→        system_prompt,
 55→        user_content,
 56→        on_event,
 57→        history,
 58→        None,
 59→        None,
 60→        None,
 61→    )
 62→    .await
 63→}
 64→
 65→/// Like `run_agent_loop` but accepts optional context values that are injected
 66→/// into every tool call's parameters (e.g. `_session_key`).
 67→pub async fn run_agent_loop_with_context(
 68→    provider: Arc<dyn LlmProvider>,
 69→    tools: &ToolRegistry,
 70→    system_prompt: &str,
 71→    user_content: &UserContent,
 72→    on_event: Option<&OnEvent>,
 73→    history: Option<Vec<ChatMessage>>,
 74→    tool_context: Option<serde_json::Value>,
 75→    hook_registry: Option<Arc<HookRegistry>>,
 76→    sender_name: Option<String>,
 77→) -> Result<AgentRunResult, AgentRunError> {
 78→    let native_tools = provider.supports_tools();
 79→    let config = moltis_config::discover_and_load();
 80→    let max_tool_result_bytes = config.tools.max_tool_result_bytes;
 81→    let max_auto_continues = config.tools.agent_max_auto_continues;
 82→    let auto_continue_min_tool_calls = config.tools.agent_auto_continue_min_tool_calls;
 83→    let compaction_ratio = config.tools.tool_result_compaction_ratio as usize;
 84→    let overflow_ratio = config.tools.preemptive_overflow_ratio as usize;
 85→    let compaction_min_iterations = config.tools.compaction_min_iterations;
 86→    let base_max_iterations = resolve_agent_max_iterations(config.tools.agent_max_iterations);
 87→    // Lazy mode needs extra iterations for tool_search discovery round-trips.
 88→    let max_iterations = if config.tools.registry_mode == moltis_config::ToolRegistryMode::Lazy {
 89→        base_max_iterations * 3
 90→    } else {
 91→        base_max_iterations
 92→    };
 93→
 94→    let is_multimodal = matches!(user_content, UserContent::Multimodal(_));
 95→    info!(
 96→        provider = provider.name(),
 97→        model = provider.id(),
 98→        native_tools,
 99→        tools_count = tools.list_names().len(),
100→        is_multimodal,
101→        "starting agent loop"
102→    );
103→
104→    let mut messages: Vec<ChatMessage> = vec![ChatMessage::system(system_prompt)];
105→
106→    // Insert conversation history before the current user message.
107→    if let Some(hist) = history {
108→        messages.extend(hist);
109→    }
110→
111→    messages.push(ChatMessage::User {
112→        content: user_content.clone(),
113→        name: sender_name,
114→    });
115→    let explicit_shell_command = explicit_shell_command_from_user_content(user_content);
116→
117→    // Extract session key once for hook payloads.
118→    let session_key_for_hooks = tool_context
119→        .as_ref()
120→        .and_then(|ctx| ctx.get("_session_key"))
121→        .and_then(|v| v.as_str())
122→        .unwrap_or("")
123→        .to_string();
124→    let channel_for_hooks =
125→        channel_binding_from_tool_context(&session_key_for_hooks, tool_context.as_ref());
126→
127→    let mut iterations = 0;
128→    let mut total_tool_calls = 0;
129→    let mut usage_accumulator = UsageAccumulator::default();
130→    let mut server_retries_remaining: u8 = 1;
131→    let mut rate_limit_retries_remaining: u8 = RATE_LIMIT_MAX_RETRIES;
132→    let mut rate_limit_backoff_ms: Option<u64> = None;
133→    let mut last_answer_text = String::new();
134→    let mut malformed_retry_count: u8 = 0;
135→    let mut empty_tool_name_retry_count: u8 = 0;
136→    let mut auto_continue_count: usize = 0;
137→    let mut loop_detector = ToolLoopDetector::new(
138→        config.tools.agent_loop_detector_window,
139→        config.tools.agent_loop_detector_strip_tools_on_second_fire,
140→    );
141→    let mut strip_tools_next_iter = false;
142→
143→    loop {
144→        iterations += 1;
145→        if iterations > max_iterations {
146→            warn!("agent loop exceeded max iterations ({})", max_iterations);
147→            return Err(AgentRunError::Other(anyhow::anyhow!(
148→                "agent loop exceeded max iterations ({})",
149→                max_iterations
150→            )));
151→        }
152→
153→        // Re-compute schemas each iteration so activated tools appear immediately.
154→        // When the loop detector has escalated to stage 2, pass an empty tool
155→        // list for this single turn so the model is forced to respond in text.
156→        let schemas_for_api = if native_tools && !strip_tools_next_iter {
157→            tools.list_schemas()
158→        } else {
159→            vec![]
160→        };
161→        if strip_tools_next_iter {
162→            strip_tools_next_iter = false;
163→            loop_detector.clear_strip_tools();
164→        }
165→
166→        let effective_ratio = if iterations > compaction_min_iterations {
167→            compaction_ratio
168→        } else {
169→            0 // skip compaction but still check for overflow
170→        };
171→        super::enforce_tool_result_context_budget(
172→            &mut messages,
173→            &schemas_for_api,
174→            provider.context_window(),
175→            effective_ratio,
176→            overflow_ratio,
177→        )?;
178→
179→        if let Some(cb) = on_event {
180→            cb(RunnerEvent::Iteration(iterations));
181→        }
182→
183→        info!(
184→            iteration = iterations,
185→            messages_count = messages.len(),
186→            "calling LLM"
187→        );
188→        trace!(iteration = iterations, messages = ?messages, "LLM request messages");
189→
190→        // Dispatch BeforeLLMCall hook — may block the LLM call.
191→        if let Some(ref hooks) = hook_registry {
192→            let msgs_json: Vec<serde_json::Value> =
193→                messages.iter().map(|m| m.to_openai_value()).collect();
194→            let payload = HookPayload::BeforeLLMCall {
195→                session_key: session_key_for_hooks.clone(),
196→                provider: provider.name().to_string(),
197→                model: provider.id().to_string(),
198→                messages: serde_json::Value::Array(msgs_json),
199→                tool_count: schemas_for_api.len(),
200→                iteration: iterations,
201→            };
202→            match hooks.dispatch(&payload).await {
203→                Ok(HookAction::Block(reason)) => {
204→                    warn!(reason = %reason, "LLM call blocked by BeforeLLMCall hook");
205→                    return Err(AgentRunError::Other(anyhow::anyhow!(
206→                        "blocked by BeforeLLMCall hook: {reason}"
207→                    )));
208→                },
209→                Ok(HookAction::ModifyPayload(_)) => {
210→                    debug!("BeforeLLMCall ModifyPayload ignored (messages are typed)");
211→                },
212→                Ok(HookAction::Continue) => {},
213→                Err(e) => {
214→                    warn!(error = %e, "BeforeLLMCall hook dispatch failed");
215→                },
216→            }
217→        }
218→
219→        if let Some(cb) = on_event {
220→            cb(RunnerEvent::Thinking);
221→        }
222→
223→        let mut response = match provider.complete(&messages, &schemas_for_api).await {
224→            Ok(r) => r,
225→            Err(e) => {
226→                let msg = e.to_string();
227→                if is_context_window_error(&msg) {
228→                    return Err(AgentRunError::ContextWindowExceeded(msg));
229→                }
230→                if let Some(delay_ms) = next_retry_delay_ms(
231→                    &msg,
232→                    &mut server_retries_remaining,
233→                    &mut rate_limit_retries_remaining,
234→                    &mut rate_limit_backoff_ms,
235→                ) {
236→                    iterations -= 1;
237→                    warn!(
238→                        error = %msg,
239→                        delay_ms,
240→                        server_retries_remaining,
241→                        rate_limit_retries_remaining,
242→                        "transient LLM error, retrying after delay"
243→                    );
244→                    if let Some(cb) = on_event {
245→                        cb(RunnerEvent::RetryingAfterError {
246→                            error: msg,
247→                            delay_ms,
248→                        });
249→                    }
250→                    tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;

250→                    tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;
251→                    continue;
252→                }
253→                return Err(AgentRunError::Other(e));
254→            },
255→        };
256→
257→        if let Some(cb) = on_event {
258→            cb(RunnerEvent::ThinkingDone);
259→        }
260→
261→        usage_accumulator.record_request(response.usage.clone());
262→
263→        info!(
264→            iteration = iterations,
265→            has_text = response.text.is_some(),
266→            tool_calls_count = response.tool_calls.len(),
267→            input_tokens = response.usage.input_tokens,
268→            output_tokens = response.usage.output_tokens,
269→            "LLM response received"
270→        );
271→        if let Some(ref text) = response.text {
272→            trace!(iteration = iterations, text = %text, "LLM response text");
273→        }
274→
275→        // Fallback: parse tool calls from model text if the provider returned
276→        // no structured tool calls (some providers/models emit text-based calls).
277→        if response.tool_calls.is_empty()
278→            && let Some(ref text) = response.text
279→        {
280→            let (parsed, remaining) = parse_tool_calls_from_text(text);
281→            if !parsed.is_empty() {
282→                info!(
283→                    native_tools,
284→                    count = parsed.len(),
285→                    first_tool = %parsed[0].name,
286→                    "parsed tool call(s) from text fallback"
287→                );
288→                response.text = remaining;
289→                response.tool_calls = parsed;
290→            }
291→        }
292→
293→        // One-shot retry for malformed tool calls: if the text looks like a
294→        // failed tool call attempt, ask the model to retry with exact format.
295→        if response.tool_calls.is_empty()
296→            && looks_like_failed_tool_call(&response.text)
297→            && malformed_retry_count == 0
298→        {
299→            malformed_retry_count += 1;
300→            info!("detected malformed tool call, requesting retry");
301→            messages.push(ChatMessage::assistant(
302→                response.text.as_deref().unwrap_or(""),
303→            ));
304→            messages.push(ChatMessage::user(MALFORMED_TOOL_RETRY_PROMPT));
305→            continue;
306→        }
307→
308→        // Fallback: recover tool calls from XML blocks (<function_call>, <tool_call>).
309→        if !native_tools
310→            && response.tool_calls.is_empty()
311→            && let Some(ref text) = response.text
312→        {
313→            let (cleaned, recovered) = recover_tool_calls_from_content(text);
314→            if !recovered.is_empty() {
315→                info!(
316→                    count = recovered.len(),
317→                    "recovered tool calls from XML blocks in response text"
318→                );
319→                response.text = if cleaned.is_empty() {
320→                    None
321→                } else {
322→                    Some(cleaned)
323→                };
324→                response.tool_calls = recovered;
325→            }
326→        }
327→
328→        // Final fallback: if the user turn is an explicit `/sh ...` command and
329→        // the model returned plain text, force one exec tool call so this path
330→        // is deterministic in the UI.
331→        if response.tool_calls.is_empty()
332→            && iterations == 1
333→            && total_tool_calls == 0
334→            && let Some(command) = explicit_shell_command.as_ref()
335→            && tools.get("exec").is_some()
336→        {
337→            info!(command = %command, "forcing exec tool call from explicit /sh command");
338→            // Preserve the model's planning/reasoning text on the assistant
339→            // tool-call message. Some providers (e.g. Moonshot thinking mode)
340→            // require this history field for follow-up tool turns.
341→            response.tool_calls = vec![ToolCall {
342→                id: new_synthetic_tool_call_id("forced"),
343→                name: "exec".to_string(),
344→                arguments: serde_json::json!({ "command": command }),
345→            }];
346→        }
347→
348→        if let Some(tc) = find_empty_tool_name_call(&response.tool_calls) {
349→            if has_named_tool_call(&response.tool_calls) {
350→                warn!(
351→                    tool_call_id = %tc.id,
352→                    "structured tool call batch contains both empty and valid tool names; preserving valid sibling tool calls and falling back to normal tool error handling"
353→                );
354→            } else if empty_tool_name_retry_count == 0 {
355→                empty_tool_name_retry_count += 1;
356→                info!(tool_call_id = %tc.id, "detected structured tool call with empty name, requesting retry");
357→                record_answer_text(&mut last_answer_text, &response.text);
358→                messages.push(ChatMessage::assistant(
359→                    response.text.as_deref().unwrap_or(""),
360→                ));
361→                messages.push(ChatMessage::user(empty_tool_name_retry_prompt(tc)));
362→                continue;
363→            }
364→            warn!(
365→                tool_call_id = %tc.id,
366→                "structured tool call still has empty name after retry; falling back to normal tool error handling"
367→            );
368→        }
369→
370→        for tc in &response.tool_calls {
371→            info!(
372→                iteration = iterations,
373→                tool_name = %tc.name,
374→                arguments = %tc.arguments,
375→                "LLM requested tool call"
376→            );
377→        }
378→
379→        // Dispatch AfterLLMCall hook — may block tool execution.
380→        dispatch_after_llm_call_hook(
381→            hook_registry.as_ref(),
382→            &session_key_for_hooks,
383→            provider.name(),
384→            provider.id(),
385→            response.text.clone(),
386→            &response.tool_calls,
387→            &response.usage,
388→            iterations,
389→        )
390→        .await?;
391→
392→        // If no tool calls, auto-continue or return the text response.
393→        if response.tool_calls.is_empty() {
394→            let response_text = response
395→                .text
396→                .clone()
397→                .filter(|t| !t.is_empty())
398→                .unwrap_or_default();
399→
400→            // Auto-continue: if the model made tool calls earlier in this run
401→            // and we haven't exhausted nudges, ask it to keep going. Suppress
402→            // the nudge when the model already produced a substantive final
403→            // answer — nudging in that case risks losing the answer (GH #628).
404→            if !is_substantive_answer_text(&response_text)
405→                && total_tool_calls > 0
406→                && total_tool_calls >= auto_continue_min_tool_calls
407→                && auto_continue_count < max_auto_continues
408→            {
409→                auto_continue_count += 1;
410→                info!(
411→                    iterations,
412→                    auto_continue_count, "model stopped without tool calls, auto-continuing"
413→                );
414→                if let Some(cb) = on_event {
415→                    cb(RunnerEvent::AutoContinue {
416→                        iteration: iterations,
417→                        max_iterations,
418→                    });
419→                }
420→                if !response_text.is_empty() {
421→                    messages.push(ChatMessage::assistant(&response_text));
422→                }
423→                messages.push(ChatMessage::user(AUTO_CONTINUE_NUDGE));
424→                continue;
425→            }
426→
427→            let text = if !response_text.is_empty() {
428→                response_text
429→            } else {
430→                std::mem::take(&mut last_answer_text)
431→            };
432→
433→            info!(
434→                iterations,
435→                tool_calls = total_tool_calls,
436→                "agent loop complete — returning text"
437→            );
438→            return Ok(finish_agent_run(
439→                text,
440→                iterations,
441→                total_tool_calls,
442→                &usage_accumulator,
443→                Vec::new(),
444→            ));
445→        }
446→
447→        // Append assistant message with tool calls.
448→        // Save any answer text for fallback — when the final iteration returns
449→        // empty, this becomes the result. Don't emit as ThinkingText because
450→        // it may be the actual answer (e.g. a table produced before a cleanup
451→        // tool call like `browser close`).
452→        record_answer_text(&mut last_answer_text, &response.text);
453→        messages.push(ChatMessage::assistant_with_tools(
454→            response.text.clone(),
455→            response.tool_calls.clone(),
456→        ));
457→
458→        // Execute tool calls concurrently.
459→        total_tool_calls += response.tool_calls.len();
460→
461→        // Build futures for all tool calls (executed concurrently).
462→        //
463→        // Pre-dispatch schema validation runs synchronously against each
464→        // tool's declared `parameters_schema`. Calls that fail validation
465→        // are short-circuited to a directive error response — the tool's
466→        // `execute` method is never invoked, and the UI receives a
467→        // `ToolCallRejected` event instead of the misleading
468→        // `ToolCallStart`/"executing" status (issue #658).
469→        let tool_futures: Vec<_> = response
470→            .tool_calls
471→            .iter()
472→            .map(|tc| {
473→                let sanitized = sanitize_tool_name(&tc.name);
474→                if *sanitized != tc.name {
475→                    debug!(original = %tc.name, sanitized = %sanitized, "sanitized mangled tool name");
476→                }
477→                let (tool, resolved_name) = resolve_tool_lookup(tools, sanitized.as_ref());
478→                if resolved_name.as_ref() != sanitized.as_ref() {
479→                    debug!(original = %sanitized, resolved = %resolved_name, "resolved legacy tool alias");
480→                }
481→                let mut args = tc.arguments.clone();
482→
483→                // Dispatch BeforeToolCall hook — may block or modify arguments.
484→                let hook_registry = hook_registry.clone();
485→                let session_key = session_key_for_hooks.clone();
486→                let channel_for_hooks = channel_for_hooks.clone();
487→                let tc_name = resolved_name.to_string();
488→                let _tc_id = tc.id.clone();
489→
490→                if let Some(ref ctx) = tool_context
491→                    && let (Some(args_obj), Some(ctx_obj)) = (args.as_object_mut(), ctx.as_object())
492→                {
493→                    for (k, v) in ctx_obj {
494→                        args_obj.insert(k.clone(), v.clone());
495→                    }
496→                }
497→
498→                // Pre-dispatch validation against the tool's schema.
499→                let validation_error: Option<String> = if let Some(ref t) = tool {
500→                    let schema = t.parameters_schema();
501→                    match validate_tool_args(&schema, &args) {
502→                        Ok(()) => None,
503→                        Err(e) => {
504→                            warn!(
505→                                tool = %tc_name,
506→                                summary = %e.short_summary(),
507→                                "tool call rejected by pre-dispatch schema validation"
508→                            );
509→                            Some(e.to_llm_error_message(&tc_name))
510→                        },
511→                    }
512→                } else {
513→                    None
514→                };
515→
516→                // Emit ToolCallStart only for calls that will actually run.
517→                // Rejected calls get a single `ToolCallRejected` event after
518→                // the concurrent batch completes (handled in the result loop).
519→                if validation_error.is_none() {
520→                    if let Some(cb) = on_event {
521→                        cb(RunnerEvent::ToolCallStart {
522→                            id: tc.id.clone(),
523→                            name: tc.name.clone(),
524→                            arguments: args.clone(),
525→                        });
526→                    }
527→                    info!(tool = %tc_name, id = %tc.id, args = %args, "executing tool");
528→                }
529→
530→                async move {
531→                    if let Some(err_msg) = validation_error {
532→                        return (
533→                            false,
534→                            serde_json::json!({ "error": err_msg.clone() }),
535→                            Some(err_msg),
536→                            true,
537→                        );
538→                    }
539→                    // Run BeforeToolCall hook.
540→                    if let Some(ref hooks) = hook_registry {
541→                        let payload = HookPayload::BeforeToolCall {
542→                            session_key: session_key.clone(),
543→                            tool_name: tc_name.clone(),
544→                            arguments: args.clone(),
545→                            channel: channel_for_hooks.clone(),
546→                        };
547→                        match hooks.dispatch(&payload).await {
548→                            Ok(HookAction::Block(reason)) => {
549→                                warn!(tool = %tc_name, reason = %reason, "tool call blocked by hook");

  1→//! Lazy tool registry: model discovers tools via `tool_search` instead of
  2→//! receiving all schemas upfront.
  3→//!
  4→//! When `registry_mode = "lazy"` is set in config, [`wrap_registry_lazy`]
  5→//! replaces the full registry with one containing only `tool_search`.
  6→//! The model calls `tool_search(query="…")` to find tools and
  7→//! `tool_search(name="tool_name")` to activate them (get the full schema).
  8→//! Activated tools appear in subsequent iterations via the runner's
  9→//! per-iteration `list_schemas()` call.
 10→
 11→use std::sync::Arc;
 12→
 13→use {anyhow::Result, async_trait::async_trait, tracing::debug};
 14→
 15→use crate::tool_registry::{ActivatedTools, AgentTool, ToolEntry, ToolRegistry, ToolSource};
 16→
 17→/// Maximum number of results returned by a keyword search.
 18→const MAX_SEARCH_RESULTS: usize = 15;
 19→
 20→/// Meta-tool that lets the model discover and activate tools from the full registry.
 21→pub struct ToolSearchTool {
 22→    /// The original full registry (read-only).
 23→    full_registry: Arc<ToolRegistry>,
 24→    /// Shared activated set — same Arc as the wrapper registry's `activated` field.
 25→    activated: ActivatedTools,
 26→}
 27→
 28→impl ToolSearchTool {
 29→    fn keyword_search(&self, query: &str) -> Vec<(String, String, u32)> {
 30→        let query_lower = query.to_lowercase();
 31→        let query_words: Vec<&str> = query_lower.split_whitespace().collect();
 32→
 33→        let mut results: Vec<(String, String, u32)> = Vec::new();
 34→
 35→        for name in self.full_registry.list_names() {
 36→            let name_lower = name.to_lowercase();
 37→            if let Some(tool) = self.full_registry.get(&name) {
 38→                let desc = tool.description().to_string();
 39→                let desc_lower = desc.to_lowercase();
 40→
 41→                let score = if name_lower == query_lower {
 42→                    100
 43→                } else if name_lower.contains(&query_lower) {
 44→                    50
 45→                } else {
 46→                    let word_matches = query_words
 47→                        .iter()
 48→                        .filter(|w| name_lower.contains(*w) || desc_lower.contains(*w))
 49→                        .count();
 50→                    if word_matches > 0 {
 51→                        (word_matches as u32) * 10
 52→                    } else {
 53→                        0
 54→                    }
 55→                };
 56→
 57→                if score > 0 {
 58→                    results.push((name, desc, score));
 59→                }
 60→            }
 61→        }
 62→
 63→        results.sort_by(|a, b| b.2.cmp(&a.2).then_with(|| a.0.cmp(&b.0)));
 64→        results.truncate(MAX_SEARCH_RESULTS);
 65→        results
 66→    }
 67→
 68→    fn activate_tool(&self, name: &str) -> Result<serde_json::Value, String> {
 69→        let tool = self
 70→            .full_registry
 71→            .get(name)
 72→            .ok_or_else(|| format!("unknown tool: {name}"))?;
 73→        let source = self
 74→            .full_registry
 75→            .get_source(name)
 76→            .unwrap_or(ToolSource::Builtin);
 77→
 78→        let schema = tool.parameters_schema();
 79→        let description = tool.description().to_string();
 80→
 81→        // Insert into activated map, preserving the original source metadata.
 82→        let mut activated = self.activated.lock().unwrap_or_else(|e| e.into_inner());
 83→        activated.insert(name.to_string(), ToolEntry { tool, source });
 84→
 85→        debug!(tool = name, "tool activated via tool_search");
 86→
 87→        Ok(serde_json::json!({
 88→            "activated": true,
 89→            "name": name,
 90→            "description": description,
 91→            "parameters": schema,
 92→            "hint": format!("Tool `{name}` is now available. Call it directly on your next turn.")
 93→        }))
 94→    }
 95→}
 96→
 97→#[async_trait]
 98→impl AgentTool for ToolSearchTool {
 99→    fn name(&self) -> &str {
100→        "tool_search"
101→    }
102→
103→    fn description(&self) -> &str {
104→        "Search for available tools by keyword, or activate a specific tool by exact name. \
105→         Use `query` to find tools (returns name + description, max 15 results). \
106→         Use `name` to activate a tool and get its full parameter schema."
107→    }
108→
109→    fn parameters_schema(&self) -> serde_json::Value {
110→        serde_json::json!({
111→            "type": "object",
112→            "properties": {
113→                "query": {
114→                    "type": "string",
115→                    "description": "Keyword to search tool names and descriptions"
116→                },
117→                "name": {
118→                    "type": "string",
119→                    "description": "Exact tool name to activate (returns full schema)"
120→                }
121→            },
122→            "additionalProperties": false
123→        })
124→    }
125→
126→    async fn execute(&self, params: serde_json::Value) -> Result<serde_json::Value> {
127→        let name = params.get("name").and_then(|v| v.as_str());
128→        let query = params.get("query").and_then(|v| v.as_str());
129→
130→        match (name, query) {
131→            (Some(name), _) => {
132→                // Activate a specific tool by name.
133→                self.activate_tool(name).map_err(|e| anyhow::anyhow!("{e}"))
134→            },
135→            (None, Some(query)) => {
136→                // Keyword search.
137→                let results = self.keyword_search(query);
138→                let items: Vec<serde_json::Value> = results
139→                    .into_iter()
140→                    .map(|(name, desc, _score)| {
141→                        serde_json::json!({
142→                            "name": name,
143→                            "description": desc
144→                        })
145→                    })
146→                    .collect();
147→                Ok(serde_json::json!({
148→                    "results": items,
149→                    "hint": "To use a tool, call tool_search again with `name` set to the exact tool name."
150→                }))

