 36→/// Tool that creates a new personal skill in `<data_dir>/skills/`.
 37→pub struct CreateSkillTool {
 38→    data_dir: PathBuf,
 39→    checkpoints: CheckpointManager,
 40→}
 41→
 42→impl CreateSkillTool {
 43→    pub fn new(data_dir: PathBuf) -> Self {
 44→        let checkpoints = CheckpointManager::new(data_dir.clone());
 45→        Self {
 46→            data_dir,
 47→            checkpoints,
 48→        }
 49→    }
 50→
 51→    fn skills_dir(&self) -> PathBuf {
 52→        self.data_dir.join("skills")
 53→    }
 54→}
 55→
 56→#[async_trait]
 57→impl AgentTool for CreateSkillTool {
 58→    fn name(&self) -> &str {
 59→        "create_skill"
 60→    }
 61→
 62→    fn description(&self) -> &str {
 63→        "Create a new personal skill. Writes a SKILL.md file to <data_dir>/skills/<name>/. \
 64→         This is persistent workspace storage (not sandbox ~/skills). \
 65→         The skill will be available on the next message automatically."
 66→    }
 67→
 68→    fn parameters_schema(&self) -> Value {
 69→        json!({
 70→            "type": "object",
 71→            "required": ["name", "description", "body"],
 72→            "properties": {
 73→                "name": {
 74→                    "type": "string",
 75→                    "description": "Skill name (lowercase, hyphens, 1-64 chars)"
 76→                },
 77→                "description": {
 78→                    "type": "string",
 79→                    "description": "Short human-readable description"
 80→                },
 81→                "body": {
 82→                    "type": "string",
 83→                    "description": "Markdown instructions for the skill"
 84→                },
 85→                "allowed_tools": {
 86→                    "type": "array",
 87→                    "items": { "type": "string" },
 88→                    "description": "Optional list of tools this skill may use"
 89→                }
 90→            }
 91→        })
 92→    }
 93→
 94→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 95→        let name = params
 96→            .get("name")
 97→            .and_then(|v| v.as_str())
 98→            .ok_or_else(|| Error::message("missing 'name'"))?;
 99→        let description = params
100→            .get("description")
101→            .and_then(|v| v.as_str())
102→            .ok_or_else(|| Error::message("missing 'description'"))?;
103→        let body = params
104→            .get("body")
105→            .and_then(|v| v.as_str())
106→            .ok_or_else(|| Error::message("missing 'body'"))?;
107→        let allowed_tools: Vec<String> = params
108→            .get("allowed_tools")
109→            .and_then(|v| v.as_array())
110→            .map(|arr| {
111→                arr.iter()
112→                    .filter_map(|v| v.as_str().map(String::from))
113→                    .collect()
114→            })
115→            .unwrap_or_default();
116→
117→        if !moltis_skills::parse::validate_name(name) {
118→            return Err(Error::message(format!(
119→                "invalid skill name '{name}': must be 1-64 lowercase alphanumeric/hyphen chars"
120→            ))
121→            .into());
122→        }
123→
124→        let skill_dir = self.skills_dir().join(name);
125→        if skill_dir.exists() {
126→            return Err(Error::message(format!(
127→                "skill '{name}' already exists; use update_skill to modify it"
128→            ))
129→            .into());
130→        }
131→
132→        let checkpoint = self
133→            .checkpoints
134→            .checkpoint_path(&skill_dir, "create_skill")
135→            .await?;
136→        let content = build_skill_md(name, description, body, &allowed_tools);
137→        write_skill(&skill_dir, &content).await?;
138→
139→        Ok(json!({
140→            "created": true,
141→            "path": skill_dir.display().to_string(),
142→            "checkpointId": checkpoint.id,
143→        }))
144→    }
145→}
