 58→pub(crate) async fn run_with_tools(
 59→    persona: PromptPersona,
 60→    state: &Arc<dyn ChatRuntime>,
 61→    model_store: &Arc<RwLock<DisabledModelsStore>>,
 62→    run_id: &str,
 63→    provider: Arc<dyn moltis_agents::model::LlmProvider>,
 64→    model_id: &str,
 65→    tool_registry: &Arc<RwLock<ToolRegistry>>,
 66→    user_content: &UserContent,
 67→    provider_name: &str,
 68→    history_raw: &[Value],
 69→    session_key: &str,
 70→    agent_id: &str,
 71→    desired_reply_medium: ReplyMedium,
 72→    project_context: Option<&str>,
 73→    runtime_context: Option<&PromptRuntimeContext>,
 74→    user_message_index: usize,
 75→    skills: &[moltis_skills::types::SkillMetadata],
 76→    hook_registry: Option<Arc<moltis_common::hooks::HookRegistry>>,
 77→    accept_language: Option<String>,
 78→    conn_id: Option<String>,
 79→    session_store: Option<&Arc<SessionStore>>,
 80→    mcp_disabled: bool,
 81→    client_seq: Option<u64>,
 82→    active_thinking_text: Option<Arc<RwLock<HashMap<String, String>>>>,
 83→    active_tool_calls: Option<Arc<RwLock<HashMap<String, Vec<ActiveToolCall>>>>>,
 84→    active_partial_assistant: Option<Arc<RwLock<HashMap<String, ActiveAssistantDraft>>>>,
 85→    active_event_forwarders: &Arc<RwLock<HashMap<String, tokio::task::JoinHandle<String>>>>,
 86→    terminal_runs: &Arc<RwLock<HashSet<String>>>,
 87→    sender_name: Option<String>,
 88→) -> Option<AssistantTurnOutput> {
 89→    let run_started = Instant::now();
 90→
 91→    let tool_mode = effective_tool_mode(&*provider);
 92→    let native_tools = matches!(tool_mode, ToolMode::Native);
 93→    let tools_enabled = !matches!(tool_mode, ToolMode::Off);
 94→
 95→    let policy_ctx = build_policy_context(agent_id, runtime_context, None);
 96→    let mut filtered_registry = {
 97→        let registry_guard = tool_registry.read().await;
 98→        if tools_enabled {
 99→            apply_runtime_tool_filters(
100→                &registry_guard,
101→                &persona.config,
102→                skills,
103→                mcp_disabled,
104→                &policy_ctx,
105→            )
106→        } else {
107→            registry_guard.clone_without(&[])
108→        }
109→    };
110→    if tools_enabled && let Some(manager) = state.memory_manager() {
111→        install_agent_scoped_memory_tools(
112→            &mut filtered_registry,
113→            manager,
114→            Arc::clone(&provider),
115→            agent_id,
116→            persona.config.memory.style,
117→            persona.config.memory.agent_write_mode,
118→        );
119→    }
120→    if tools_enabled
121→        && matches!(
122→            persona.config.tools.registry_mode,
123→            moltis_config::ToolRegistryMode::Lazy
124→        )
125→    {
126→        filtered_registry = moltis_agents::lazy_tools::wrap_registry_lazy(filtered_registry);
127→    }
128→
129→    // Build system prompt:
130→    // - Native tools: full prompt with tool schemas sent via API
131→    // - Text tools: full prompt with tool schemas embedded + call guidance
132→    // - Off: minimal prompt without tools
133→    let prompt_limits = prompt_build_limits_from_config(&persona.config);
134→    let system_prompt = if tools_enabled {
135→        build_system_prompt_with_session_runtime_details(
136→            &filtered_registry,
137→            native_tools,
138→            project_context,
