 86→/// Scan one level deep for SKILL.md dirs (project/personal sources).
 87→fn discover_flat(base_path: &Path, source: &SkillSource, skills: &mut Vec<SkillMetadata>) {
 88→    let entries = match std::fs::read_dir(base_path) {
 89→        Ok(e) => e,
 90→        Err(_) => return,
 91→    };
 92→
 93→    for entry in entries.flatten() {
 94→        let skill_dir = entry.path();
 95→        if !skill_dir.is_dir() {
 96→            continue;
 97→        }
 98→        let skill_md = skill_dir.join("SKILL.md");
 99→        if !skill_md.is_file() {
100→            continue;
101→        }
102→        let content = match std::fs::read_to_string(&skill_md) {
103→            Ok(c) => c,
104→            Err(e) => {
105→                tracing::warn!(?skill_md, %e, "failed to read SKILL.md");
106→                continue;
107→            },
108→        };
109→        match parse::parse_metadata(&content, &skill_dir) {
110→            Ok(mut meta) => {
111→                meta.source = Some(source.clone());
112→                tracing::debug!(
113→                    path = %skill_md.display(),
114→                    source = ?source,
115→                    name = %meta.name,
116→                    "loaded SKILL.md"
117→                );
118→                skills.push(meta);
119→            },
120→            Err(e) => {
121→                tracing::warn!(?skill_dir, %e, "failed to parse SKILL.md");
122→            },
123→        }
124→    }
125→}
