127→/// Discover enabled plugin skills using the plugins manifest.
128→/// Plugin skills don't have SKILL.md — they are normalized by format adapters.
129→/// This returns lightweight metadata from the manifest for prompt injection.
130→fn discover_plugins(install_dir: &Path, skills: &mut Vec<SkillMetadata>) {
131→    let manifest_path = moltis_config::data_dir().join("plugins-manifest.json");
132→    let store = ManifestStore::new(manifest_path);
133→    let manifest = match store.load() {
134→        Ok(m) => m,
135→        Err(e) => {
136→            tracing::warn!(%e, "failed to load plugins manifest");
137→            return;
138→        },
139→    };
140→
141→    for repo in &manifest.repos {
142→        for skill_state in &repo.skills {
143→            if !skill_state.enabled || !skill_state.trusted {
144→                continue;
145→            }
146→            let skill_dir = install_dir.join(&skill_state.relative_path);
147→            skills.push(SkillMetadata {
148→                name: skill_state.name.clone(),
149→                path: skill_dir,
150→                source: Some(SkillSource::Plugin),
151→                ..Default::default()
152→            });
153→        }
154→    }
155→}
