157→/// Discover registry skills using the manifest for enabled filtering.
158→///
159→/// Handles both formats:
160→/// - `PluginFormat::Skill` → parse `SKILL.md` from disk for full metadata
161→/// - Other formats → create stub metadata with `SkillSource::Plugin` (prompt_gen
162→///   uses the path as-is instead of appending `/SKILL.md`)
163→fn discover_registry(install_dir: &Path, skills: &mut Vec<SkillMetadata>) {
164→    let manifest_path = match ManifestStore::default_path() {
165→        Ok(p) => p,
166→        Err(_) => return,
167→    };
168→    let store = ManifestStore::new(manifest_path);
169→    let manifest = match store.load() {
170→        Ok(m) => m,
171→        Err(e) => {
172→            tracing::warn!(%e, "failed to load skills manifest");
173→            return;
174→        },
175→    };
176→
177→    for repo in &manifest.repos {
178→        for skill_state in &repo.skills {
179→            if !skill_state.enabled || !skill_state.trusted {
180→                continue;
181→            }
182→            let skill_dir = install_dir.join(&skill_state.relative_path);
183→
184→            match repo.format {
185→                PluginFormat::Skill => {
186→                    let skill_md = skill_dir.join("SKILL.md");
187→                    if !skill_md.is_file() {
188→                        tracing::warn!(?skill_md, "manifest references missing SKILL.md");
189→                        continue;
190→                    }
191→                    let content = match std::fs::read_to_string(&skill_md) {
192→                        Ok(c) => c,
193→                        Err(e) => {
194→                            tracing::warn!(?skill_md, %e, "failed to read SKILL.md");
195→                            continue;
196→                        },
197→                    };
198→                    match parse::parse_metadata(&content, &skill_dir) {
199→                        Ok(mut meta) => {
200→                            meta.source = Some(SkillSource::Registry);
201→                            tracing::debug!(
202→                                path = %skill_md.display(),
203→                                source = "registry",
204→                                name = %meta.name,
205→                                "loaded SKILL.md"
206→                            );
207→                            skills.push(meta);
208→                        },
209→                        Err(e) => {
210→                            tracing::debug!(?skill_dir, %e, "skipping non-conforming SKILL.md");
211→                        },
212→                    }
213→                },
214→                _ => {
215→                    // Non-SKILL.md formats: stub metadata with Plugin source
216→                    // so prompt_gen uses the path directly (no /SKILL.md append).
217→                    skills.push(SkillMetadata {
218→                        name: skill_state.name.clone(),
219→                        path: skill_dir,
220→                        source: Some(SkillSource::Plugin),
221→                        ..Default::default()
222→                    });
223→                },
224→            }
225→        }
226→    }
227→}
