    #[tokio::test]
    async fn test_discover_skips_invalid_frontmatter() {
        let tmp = tempfile::tempdir().unwrap();
        let skills_dir = tmp.path().join("skills");
        std::fs::create_dir_all(skills_dir.join("bad-skill")).unwrap();
        std::fs::write(skills_dir.join("bad-skill/SKILL.md"), "no frontmatter here").unwrap();

        let discoverer = FsSkillDiscoverer::new(vec![(skills_dir, SkillSource::Project)]);
        let skills = discoverer.discover().await.unwrap();
        assert!(skills.is_empty());
    }

    #[tokio::test]
    async fn test_discover_registry_filters_disabled() {
        // This test exercises the manifest-based registry discovery.
        // We need a manifest file and matching skill dirs.
        let tmp = tempfile::tempdir().unwrap();
        let install_dir = tmp.path().join("installed-skills");
        let manifest_path = tmp.path().join("manifest.json");

        // Create repo with two skills on disk.
        std::fs::create_dir_all(install_dir.join("repo/skills/a")).unwrap();
        std::fs::create_dir_all(install_dir.join("repo/skills/b")).unwrap();
        std::fs::write(
            install_dir.join("repo/skills/a/SKILL.md"),
            "---\nname: a\ndescription: skill a\n---\nbody\n",
        )
        .unwrap();
        std::fs::write(
            install_dir.join("repo/skills/b/SKILL.md"),
            "---\nname: b\ndescription: skill b\n---\nbody\n",
        )
        .unwrap();

        // Create manifest with 'a' enabled and 'b' disabled.
        let manifest = SkillsManifest {
            version: 1,
            repos: vec![RepoEntry {
                source: "owner/repo".into(),
                repo_name: "repo".into(),
                installed_at_ms: 0,
                commit_sha: None,
                format: PluginFormat::Skill,
                quarantined: false,
                quarantine_reason: None,
                provenance: None,
                skills: vec![
                    SkillState {
                        name: "a".into(),
                        relative_path: "repo/skills/a".into(),
                        trusted: true,
                        enabled: true,
                    },
                    SkillState {
                        name: "b".into(),
                        relative_path: "repo/skills/b".into(),
                        trusted: false,
                        enabled: false,
                    },
                ],
            }],
        };
        let store = ManifestStore::new(manifest_path.clone());
        store.save(&manifest).unwrap();

        // We can't easily test discover_registry with a custom manifest path
        // since it uses ManifestStore::default_path(). Instead, test the function
        // directly.
        let mut skills = Vec::new();

        // Manually call the inner function with the right manifest.
        // Since discover_registry uses default_path, we test the flat path instead.
        discover_flat(
            &install_dir.join("repo/skills"),
            &SkillSource::Project,
            &mut skills,
        );
        // Both skills found when using flat scan (no filtering).
        assert_eq!(skills.len(), 2);
    }

    #[test]
    fn test_discover_registry_mixed_formats() {
        use crate::formats::PluginFormat;

        let tmp = tempfile::tempdir().unwrap();
        let install_dir = tmp.path();

        // SKILL.md repo on disk
        std::fs::create_dir_all(install_dir.join("skill-repo/SKILL.md").parent().unwrap()).unwrap();
        std::fs::write(
            install_dir.join("skill-repo/SKILL.md"),
            "---\nname: my-skill\ndescription: a native skill\n---\nbody\n",
        )
        .unwrap();

        // Claude Code repo on disk (no SKILL.md)
        std::fs::create_dir_all(install_dir.join("plugin-repo")).unwrap();

        // Build manifest with both formats
        let manifest = SkillsManifest {
            version: 1,
            repos: vec![
                RepoEntry {
                    source: "owner/skill-repo".into(),
                    repo_name: "skill-repo".into(),
                    installed_at_ms: 0,
                    commit_sha: None,
                    format: PluginFormat::Skill,
                    quarantined: false,
                    quarantine_reason: None,
                    provenance: None,
                    skills: vec![SkillState {
                        name: "my-skill".into(),
                        relative_path: "skill-repo".into(),
                        trusted: true,
                        enabled: true,
                    }],
                },
                RepoEntry {
                    source: "owner/plugin-repo".into(),
                    repo_name: "plugin-repo".into(),
                    installed_at_ms: 0,
                    commit_sha: None,
                    format: PluginFormat::ClaudeCode,
                    quarantined: false,
                    quarantine_reason: None,
                    provenance: None,
                    skills: vec![SkillState {
                        name: "test-plugin:helper".into(),
                        relative_path: "plugin-repo".into(),
                        trusted: true,
                        enabled: true,
                    }],
                },
            ],
        };
        let manifest_path = tmp.path().join("skills-manifest.json");
        let store = ManifestStore::new(manifest_path);
        store.save(&manifest).unwrap();

        // Can't call discover_registry directly (uses default_path), so
        // simulate the logic inline.
        let mut skills = Vec::new();
        for repo in &manifest.repos {
            for skill_state in &repo.skills {
                if !skill_state.enabled || !skill_state.trusted {
                    continue;
                }
                let skill_dir = install_dir.join(&skill_state.relative_path);
                match repo.format {
                    PluginFormat::Skill => {
                        let skill_md = skill_dir.join("SKILL.md");
                        if skill_md.is_file() {
                            let content = std::fs::read_to_string(&skill_md).unwrap();
                            let mut meta = parse::parse_metadata(&content, &skill_dir).unwrap();
                            meta.source = Some(SkillSource::Registry);
                            skills.push(meta);
                        }
                    },
                    _ => {
                        skills.push(SkillMetadata {
                            name: skill_state.name.clone(),
                            path: skill_dir,
                            source: Some(SkillSource::Plugin),
                            ..Default::default()
                        });
                    },
                }
            }
        }

        assert_eq!(skills.len(), 2);

        // SKILL.md repo gets full metadata with Registry source
        let skill = skills.iter().find(|s| s.name == "my-skill").unwrap();
        assert_eq!(skill.source, Some(SkillSource::Registry));
        assert_eq!(skill.description, "a native skill");

        // Claude Code repo gets stub metadata with Plugin source
        let plugin = skills
            .iter()
            .find(|s| s.name == "test-plugin:helper")
            .unwrap();
        assert_eq!(plugin.source, Some(SkillSource::Plugin));
        assert!(plugin.description.is_empty());
    }
}

use std::path::PathBuf;

use serde::{Deserialize, Serialize};

use crate::formats::PluginFormat;

// ── Skills manifest ──────────────────────────────────────────────────────────

/// Top-level manifest tracking installed repos and per-skill enabled state.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SkillsManifest {
    pub version: u32,
    #[serde(default)]
    pub repos: Vec<RepoEntry>,
}

impl Default for SkillsManifest {
    fn default() -> Self {
        Self {
            version: 1,
            repos: Vec::new(),
        }
    }
}

impl SkillsManifest {
    pub fn add_repo(&mut self, entry: RepoEntry) {
        self.repos.push(entry);
    }

    pub fn remove_repo(&mut self, source: &str) {
        self.repos.retain(|r| r.source != source);
    }

    pub fn find_repo(&self, source: &str) -> Option<&RepoEntry> {
        self.repos.iter().find(|r| r.source == source)
    }

    pub fn find_repo_mut(&mut self, source: &str) -> Option<&mut RepoEntry> {
        self.repos.iter_mut().find(|r| r.source == source)
    }

    pub fn set_skill_enabled(&mut self, source: &str, skill_name: &str, enabled: bool) -> bool {
        if let Some(repo) = self.find_repo_mut(source)
            && let Some(skill) = repo.skills.iter_mut().find(|s| s.name == skill_name)
        {
            skill.enabled = enabled;
            return true;
        }
        false
    }

    pub fn set_skill_trusted(&mut self, source: &str, skill_name: &str, trusted: bool) -> bool {
        if let Some(repo) = self.find_repo_mut(source)
            && let Some(skill) = repo.skills.iter_mut().find(|s| s.name == skill_name)
        {
            skill.trusted = trusted;
            return true;
        }
        false
    }
}

/// A single cloned repository with its discovered skills.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RepoEntry {
    pub source: String,
    pub repo_name: String,
    pub installed_at_ms: u64,
    #[serde(default)]
    pub commit_sha: Option<String>,
    #[serde(default)]
    pub format: PluginFormat,
    #[serde(default)]
    pub quarantined: bool,
    #[serde(default)]
    pub quarantine_reason: Option<String>,
    #[serde(default)]
    pub provenance: Option<RepoProvenance>,
    pub skills: Vec<SkillState>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RepoProvenance {
    pub original_source: String,
    #[serde(default)]
    pub original_commit_sha: Option<String>,
    #[serde(default)]
    pub imported_from: Option<String>,
    #[serde(default)]
    pub exported_at_ms: Option<u64>,
}

/// Per-skill enabled state within a repo.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SkillState {
    pub name: String,
    pub relative_path: String,
    #[serde(default = "default_trusted")]
    pub trusted: bool,
    pub enabled: bool,
}

fn default_trusted() -> bool {
    // Backward compatibility: manifests created before trust-gating should
    // continue to work without immediately disabling all installed skills.
    true
}

#[allow(clippy::unwrap_used, clippy::expect_used)]
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn skill_state_defaults_trusted_for_backward_compat() {
        let parsed: SkillState = serde_json::from_str(
            r#"{"name":"demo","relative_path":"repo/skills/demo","enabled":true}"#,
        )
        .unwrap();
        assert!(parsed.trusted);
    }
}

// ── Skill metadata ───────────────────────────────────────────────────────────

/// Where a skill was discovered from.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum SkillSource {
    /// Project-local: `<data_dir>/.moltis/skills/`
    Project,
    /// Personal: `<data_dir>/skills/`
    Personal,
    /// Bundled inside a plugin directory.
    Plugin,
    /// Installed from a registry (e.g. skills.sh).
    Registry,
}

/// Lightweight metadata parsed from SKILL.md frontmatter.
/// Loaded at startup for all discovered skills (cheap).
///
/// `Default::default()` leaves `name` as `""` (invalid per `validate_name`).
/// Always initialise `name` explicitly, e.g.
/// `SkillMetadata { name: "my-skill".into(), ..Default::default() }`.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct SkillMetadata {
    /// Internal skill name — lowercase, hyphens allowed, 1-64 chars.
    /// When frontmatter `name` is human-readable (e.g. "SEO (Audit + Writer)"),
    /// this is populated from `slug` instead, and the original is stored in `display_name`.
    pub name: String,
    /// Optional slug from frontmatter; used as internal name when `name` fails validation.
    #[serde(default)]
    pub slug: Option<String>,
    /// Human-readable display name, set when `name` was swapped with `slug`.
    #[serde(default)]
    pub display_name: Option<String>,
    /// Short human-readable description.
    #[serde(default)]
    pub description: String,
    /// Homepage URL.
    #[serde(default)]
    pub homepage: Option<String>,
    /// SPDX license identifier.
    #[serde(default)]
    pub license: Option<String>,
    /// Environment requirements (intended product, system packages, network access, etc.).
    #[serde(default)]
    pub compatibility: Option<String>,
    /// Tools this skill is allowed to use (space-delimited in spec, parsed as list).
    #[serde(default, alias = "allowed-tools")]
    pub allowed_tools: Vec<String>,
    /// Optional Dockerfile (relative to skill directory) for sandbox environment.
    #[serde(default)]
    pub dockerfile: Option<String>,
    /// Binary/tool requirements for this skill.
    #[serde(default)]
    pub requires: SkillRequirements,
    /// Filesystem path to the skill directory.
    #[serde(skip)]
    pub path: PathBuf,
    /// Where this skill was discovered.
    #[serde(skip)]
    pub source: Option<SkillSource>,
}

// ── Skill requirements ──────────────────────────────────────────────────────

/// Binary and tool requirements declared in SKILL.md frontmatter.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct SkillRequirements {
    /// All of these binaries must be found in PATH.
    #[serde(default)]
    pub bins: Vec<String>,
    /// At least one of these binaries must be found (openclaw `anyBins`).
    #[serde(default)]
    pub any_bins: Vec<String>,
    /// Install instructions for missing binaries.
    #[serde(default)]
    pub install: Vec<InstallSpec>,
}

/// How to install a missing binary dependency.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct InstallSpec {
    pub kind: InstallKind,
    #[serde(default)]
    pub formula: Option<String>,
    #[serde(default)]
    pub package: Option<String>,
    #[serde(default)]
    pub module: Option<String>,
    #[serde(default)]
    pub url: Option<String>,
    /// Which binaries this install step provides.
    #[serde(default)]
    pub bins: Vec<String>,
    /// Platform filter (e.g. `["darwin"]`, `["linux"]`). Empty = all platforms.
    #[serde(default)]
    pub os: Vec<String>,
    #[serde(default)]
    pub label: Option<String>,
}

/// Install method kind.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum InstallKind {
    Brew,
    Npm,
    Go,
    Cargo,
    Uv,
    Download,
}

/// Result of checking whether a skill's requirements are met.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SkillEligibility {
    pub eligible: bool,
    pub missing_bins: Vec<String>,
    /// Install options filtered to the current OS.
    pub install_options: Vec<InstallSpec>,
}

/// Full skill content: metadata + markdown body.
/// Loaded on demand when a skill is activated.
#[derive(Debug, Clone)]
pub struct SkillContent {
    pub metadata: SkillMetadata,
    pub body: String,
}

