  9→/// Validate a skill name: lowercase ASCII, hyphens, 1-64 chars.
 10→pub fn validate_name(name: &str) -> bool {
 11→    !name.is_empty()
 12→        && name.len() <= 64
 13→        && name
 14→            .chars()
 15→            .all(|c| c.is_ascii_lowercase() || c.is_ascii_digit() || c == '-' || c == ':')
 16→        && !name.starts_with('-')
 17→        && !name.ends_with('-')
 18→        && !name.starts_with(':')
 19→        && !name.ends_with(':')
 20→        && !name.contains("--")
 21→        && !name.contains("::")
 22→}
 23→
 24→/// When `name` fails validation, try to use `slug` (from frontmatter or `_meta.json`)
 25→/// as the internal name, storing the original `name` as `display_name`.
 26→fn resolve_name_or_slug(meta: &mut SkillMetadata, skill_dir: &Path) -> Result<()> {
 27→    if validate_name(&meta.name) {
 28→        return Ok(());
 29→    }
 30→
 31→    // Try slug from frontmatter first.
 32→    let slug = meta.slug.clone().or_else(|| {
 33→        // Fall back to slug from _meta.json.
 34→        read_meta_json(skill_dir).and_then(|m| m.slug)
 35→    });
 36→
 37→    match slug {
 38→        Some(ref s) if validate_name(s) => {
 39→            tracing::debug!(
 40→                name = %meta.name,
 41→                slug = %s,
 42→                "skill name invalid, using slug as internal name"
 43→            );
 44→            meta.display_name = Some(std::mem::take(&mut meta.name));
 45→            meta.name = s.clone();
 46→            // slug is intentionally left populated so callers can inspect what was in the frontmatter.
 47→            Ok(())
 48→        },
 49→        Some(ref s) => {
 50→            let source = if meta.slug.is_some() {
 51→                "frontmatter"
 52→            } else {
 53→                "_meta.json"
 54→            };
 55→            Err(Error::Validation(format!(
 56→                "skill name '{}' is invalid and slug '{}' (from {}) is also invalid: \
 57→                 must be 1-64 lowercase alphanumeric, hyphen, or colon chars \
 58→                 (e.g. 'my-skill' or 'ns:skill')",
 59→                meta.name, s, source
 60→            )))
 61→        },
 62→        None => Err(Error::Validation(format!(
 63→            "skill name '{}' is invalid and no slug provided: \
 64→             must be 1-64 lowercase alphanumeric, hyphen, or colon chars \
 65→             (e.g. 'my-skill' or 'ns:skill'), \
 66→             or provide a valid 'slug' field",
 67→            meta.name
 68→        ))),
 69→    }
 70→}
 71→
 72→/// Parse a SKILL.md file into metadata only (frontmatter).
 73→pub fn parse_metadata(content: &str, skill_dir: &Path) -> Result<SkillMetadata> {
 74→    let (frontmatter, _body) = split_frontmatter(content)?;
 75→    let mut meta: SkillMetadata = serde_yaml::from_str(&frontmatter)
 76→        .map_err(|e| Error::Parse(format!("invalid SKILL.md frontmatter: {e}")))?;
 77→
 78→    resolve_name_or_slug(&mut meta, skill_dir)?;
 79→
 80→    merge_openclaw_requires(&frontmatter, &mut meta);
 81→    meta.path = skill_dir.to_path_buf();
 82→    Ok(meta)
 83→}
 84→
 85→/// Parse a SKILL.md file into full content (metadata + body).
 86→pub fn parse_skill(content: &str, skill_dir: &Path) -> Result<SkillContent> {
 87→    let (frontmatter, body) = split_frontmatter(content)?;
 88→    let mut meta: SkillMetadata = serde_yaml::from_str(&frontmatter)
 89→        .map_err(|e| Error::Parse(format!("invalid SKILL.md frontmatter: {e}")))?;
 90→
 91→    resolve_name_or_slug(&mut meta, skill_dir)?;
 92→
 93→    merge_openclaw_requires(&frontmatter, &mut meta);
 94→    meta.path = skill_dir.to_path_buf();
 95→    Ok(SkillContent {
 96→        metadata: meta,
 97→        body: body.to_string(),
 98→    })
 99→}
