101→// ── OpenClaw metadata extraction ────────────────────────────────────────────
102→
103→/// Helper struct to extract `metadata.openclaw.requires` and `metadata.openclaw.install`.
104→#[derive(Deserialize, Default)]
105→struct OpenClawRoot {
106→    #[serde(default)]
107→    metadata: Option<OpenClawMetadataWrap>,
108→}
109→
110→#[derive(Deserialize, Default)]
111→struct OpenClawMetadataWrap {
112→    /// Our own namespace.
113→    #[serde(default)]
114→    openclaw: Option<OpenClawMeta>,
115→    /// Original openclaw/clawdbot namespace.
116→    #[serde(default)]
117→    clawdbot: Option<OpenClawMeta>,
118→    /// Moltbot namespace (some openclaw skills use this).
119→    #[serde(default)]
120→    moltbot: Option<OpenClawMeta>,
121→}
122→
123→#[derive(Deserialize, Default)]
124→struct OpenClawMeta {
125→    #[serde(default)]
126→    requires: Option<OpenClawRequires>,
127→    #[serde(default)]
128→    install: Vec<OpenClawInstallSpec>,
129→}
130→
131→#[derive(Deserialize, Default)]
132→struct OpenClawRequires {
133→    #[serde(default)]
134→    bins: Vec<String>,
135→    #[serde(default, rename = "anyBins")]
136→    any_bins: Vec<String>,
137→}
138→
139→#[derive(Deserialize)]
140→struct OpenClawInstallSpec {
141→    #[serde(default)]
142→    kind: String,
143→    #[serde(default)]
144→    formula: Option<String>,
145→    #[serde(default)]
146→    package: Option<String>,
147→    /// openclaw uses `pkg` for go/cargo installs.
148→    #[serde(default)]
149→    pkg: Option<String>,
150→    #[serde(default, rename = "module")]
151→    module_path: Option<String>,
152→    #[serde(default)]
153→    url: Option<String>,
154→    #[serde(default)]
155→    bins: Vec<String>,
156→    #[serde(default)]
157→    os: Vec<String>,
158→    #[serde(default)]
159→    label: Option<String>,
160→}
161→
162→/// If the top-level `requires` is empty but `metadata.openclaw.requires`/`install` exist,
163→/// merge them into `SkillMetadata.requires`.
164→fn merge_openclaw_requires(frontmatter: &str, meta: &mut SkillMetadata) {
165→    // Only merge if top-level requires is empty
166→    if !meta.requires.bins.is_empty()
167→        || !meta.requires.any_bins.is_empty()
168→        || !meta.requires.install.is_empty()
169→    {
170→        return;
171→    }
172→
173→    let root: OpenClawRoot = match serde_yaml::from_str(frontmatter) {
174→        Ok(r) => r,
175→        Err(_) => return,
176→    };
177→
178→    let oc = match root
179→        .metadata
180→        .and_then(|m| m.openclaw.or(m.clawdbot).or(m.moltbot))
181→    {
182→        Some(oc) => oc,
183→        None => return,
184→    };
185→
186→    if let Some(req) = oc.requires {
187→        meta.requires.bins = req.bins;
188→        meta.requires.any_bins = req.any_bins;
189→    }
190→
191→    fn parse_kind(s: &str) -> Option<InstallKind> {
192→        match s {
193→            "brew" => Some(InstallKind::Brew),
194→            "npm" => Some(InstallKind::Npm),
195→            "go" => Some(InstallKind::Go),
196→            "cargo" => Some(InstallKind::Cargo),
197→            "uv" => Some(InstallKind::Uv),
198→            "download" => Some(InstallKind::Download),
199→            _ => None,
200→        }
201→    }
202→
203→    for spec in oc.install {
204→        if let Some(kind) = parse_kind(&spec.kind) {
205→            meta.requires.install.push(InstallSpec {
206→                kind: kind.clone(),
207→                formula: spec.formula,
208→                package: spec.package.or_else(|| {
209→                    if kind == InstallKind::Npm || kind == InstallKind::Cargo {
210→                        spec.pkg.clone()
211→                    } else {
212→                        None
213→                    }
214→                }),
215→                module: spec.module_path.or_else(|| {
216→                    if kind == InstallKind::Go {
217→                        spec.pkg.clone()
218→                    } else {
219→                        None
220→                    }
221→                }),
222→                url: spec.url,
223→                bins: spec.bins,
224→                os: spec.os,
225→                label: spec.label,
226→            });
227→        }
228→    }
229→}
