 891→#[derive(Debug, Clone)]
 892→struct ValidatedSkillFile {
 893→    relative_path: PathBuf,
 894→    content: String,
 895→}
 896→
 897→#[async_trait]
 898→impl AgentTool for WriteSkillFilesTool {
 899→    fn name(&self) -> &str {
 900→        "write_skill_files"
 901→    }
 902→
 903→    fn description(&self) -> &str {
 904→        "Write supplementary UTF-8 text files inside an existing personal skill directory. \
 905→         This tool is disabled by default and only appears when skills.enable_agent_sidecar_files is enabled."
 906→    }
 907→
 908→    fn parameters_schema(&self) -> Value {
 909→        json!({
 910→            "type": "object",
 911→            "required": ["name", "files"],
 912→            "properties": {
 913→                "name": {
 914→                    "type": "string",
 915→                    "description": "Existing skill name to update"
 916→                },
 917→                "files": {
 918→                    "type": "array",
 919→                    "description": "Supplementary text files to write inside the skill directory",
 920→                    "minItems": 1,
 921→                    "maxItems": MAX_SIDECAR_FILES_PER_CALL,
 922→                    "items": {
 923→                        "type": "object",
 924→                        "required": ["path", "content"],
 925→                        "properties": {
 926→                            "path": {
 927→                                "type": "string",
 928→                                "description": "Relative path inside the skill directory"
 929→                            },
 930→                            "content": {
 931→                                "type": "string",
 932→                                "description": "UTF-8 text content to write"
 933→                            }
 934→                        }
 935→                    }
 936→                }
 937→            }
 938→        })
 939→    }
 940→
 941→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 942→        let name = params
 943→            .get("name")
 944→            .and_then(|v| v.as_str())
 945→            .ok_or_else(|| Error::message("missing 'name'"))?;
 946→
 947→        if !moltis_skills::parse::validate_name(name) {
 948→            return Err(Error::message(format!(
 949→                "invalid skill name '{name}': must be 1-64 lowercase alphanumeric/hyphen chars"
 950→            ))
 951→            .into());
 952→        }
 953→
 954→        let files = params
 955→            .get("files")
 956→            .and_then(|v| v.as_array())
 957→            .ok_or_else(|| Error::message("missing 'files'"))?;
 958→        let validated = validate_sidecar_files(files)?;
 959→
 960→        let skill_dir = self.skills_dir().join(name);
 961→        if !skill_dir.exists() {
 962→            return Err(Error::message(format!(
 963→                "skill '{name}' does not exist; use create_skill first"
 964→            ))
 965→            .into());
 966→        }
 967→
 968→        let checkpoint = self
 969→            .checkpoints
 970→            .checkpoint_path(&skill_dir, "write_skill_files")
 971→            .await?;
 972→        write_sidecar_files(&skill_dir, &validated).await?;
 973→        audit_sidecar_file_write(&self.data_dir, name, &validated);
 974→
 975→        Ok(json!({
 976→            "written": true,
 977→            "path": skill_dir.display().to_string(),
 978→            "checkpointId": checkpoint.id,
 979→            "files_written": validated.len(),
 980→            "files": validated.iter().map(|file| file.relative_path.display().to_string()).collect::<Vec<_>>(),
 981→        }))
 982→    }
 983→}
