 985→fn build_skill_md(name: &str, description: &str, body: &str, allowed_tools: &[String]) -> String {
 986→    let mut frontmatter = format!("---\nname: {name}\ndescription: {description}\n");
 987→    if !allowed_tools.is_empty() {
 988→        frontmatter.push_str("allowed_tools:\n");
 989→        for tool in allowed_tools {
 990→            frontmatter.push_str(&format!("  - {tool}\n"));
 991→        }
 992→    }
 993→    frontmatter.push_str("---\n\n");
 994→    frontmatter.push_str(body);
 995→    if !body.ends_with('\n') {
 996→        frontmatter.push('\n');
 997→    }
 998→    frontmatter
 999→}
1000→
1001→async fn write_skill(skill_dir: &Path, content: &str) -> crate::Result<()> {
1002→    tokio::fs::create_dir_all(skill_dir).await?;
1003→    tokio::fs::write(skill_dir.join("SKILL.md"), content).await?;
1004→    Ok(())
1005→}
1006→
1007→fn validate_sidecar_files(files: &[Value]) -> anyhow::Result<Vec<ValidatedSkillFile>> {
1008→    if files.is_empty() {
1009→        return Err(Error::message("at least one file is required").into());
1010→    }
1011→    if files.len() > MAX_SIDECAR_FILES_PER_CALL {
1012→        return Err(Error::message(format!(
1013→            "too many files: maximum is {MAX_SIDECAR_FILES_PER_CALL}"
1014→        ))
1015→        .into());
1016→    }
1017→
1018→    let mut total_bytes = 0usize;
1019→    let mut seen_paths = HashSet::new();
1020→    let mut validated = Vec::with_capacity(files.len());
1021→
1022→    for file in files {
1023→        let path = file
1024→            .get("path")
1025→            .and_then(|v| v.as_str())
1026→            .ok_or_else(|| Error::message("each file needs a string 'path'"))?;
1027→        let content = file
1028→            .get("content")
1029→            .and_then(|v| v.as_str())
1030→            .ok_or_else(|| Error::message("each file needs a string 'content'"))?;
1031→
1032→        let relative_path = normalize_relative_skill_file_path(path)?;
1033→        if !seen_paths.insert(relative_path.clone()) {
1034→            return Err(Error::message(format!(
1035→                "duplicate file path '{}'",
1036→                relative_path.display()
1037→            ))
1038→            .into());
1039→        }
1040→
1041→        let file_bytes = content.len();
1042→        if file_bytes > MAX_SIDECAR_FILE_BYTES {
1043→            return Err(Error::message(format!(
1044→                "file '{}' exceeds maximum size of {MAX_SIDECAR_FILE_BYTES} bytes",
1045→                relative_path.display()
1046→            ))
1047→            .into());
1048→        }
1049→
1050→        total_bytes += file_bytes;
1051→        if total_bytes > MAX_SIDECAR_TOTAL_BYTES {
1052→            return Err(Error::message(format!(
1053→                "total file content exceeds maximum size of {MAX_SIDECAR_TOTAL_BYTES} bytes"
1054→            ))
1055→            .into());
1056→        }
1057→
1058→        validated.push(ValidatedSkillFile {
1059→            relative_path,
1060→            content: content.to_string(),
1061→        });
1062→    }
1063→
1064→    Ok(validated)
1065→}
1066→
1067→fn normalize_relative_skill_file_path(path: &str) -> anyhow::Result<PathBuf> {
1068→    let trimmed = path.trim();
1069→    if trimmed.is_empty() {
1070→        return Err(Error::message("file path must not be empty").into());
1071→    }
1072→
1073→    let candidate = Path::new(trimmed);
1074→    if candidate.is_absolute() {
1075→        return Err(Error::message("file path must be relative").into());
1076→    }
1077→
1078→    let mut normalized = PathBuf::new();
1079→    for component in candidate.components() {
1080→        match component {
1081→            Component::Normal(segment) => {
1082→                let Some(segment_str) = segment.to_str() else {
1083→                    return Err(Error::message("file path must be valid UTF-8").into());
1084→                };
1085→                if segment_str.starts_with('.') {
1086→                    return Err(Error::message(format!(
1087→                        "hidden path components are not allowed: '{trimmed}'"
1088→                    ))
1089→                    .into());
1090→                }
1091→                normalized.push(segment);
1092→            },
1093→            Component::CurDir => {},
1094→            Component::ParentDir | Component::RootDir | Component::Prefix(_) => {
1095→                return Err(Error::message("path traversal is not allowed").into());
1096→            },
1097→        }
1098→    }
1099→
1100→    let Some(file_name) = normalized.file_name().and_then(|name| name.to_str()) else {
1101→        return Err(Error::message("file path must name a file").into());
1102→    };
1103→
1104→    if file_name.eq_ignore_ascii_case("SKILL.md") {
1105→        return Err(
1106→            Error::message("SKILL.md must be managed with create_skill/update_skill").into(),
1107→        );
1108→    }
1109→
1110→    Ok(normalized)
1111→}
1112→
1113→async fn write_sidecar_files(skill_dir: &Path, files: &[ValidatedSkillFile]) -> crate::Result<()> {
1114→    // Anchor the confinement check to the canonical *skills root*, not the
1115→    // skill directory itself.  If `<data_dir>/skills/<name>` were a symlink
1116→    // pointing outside the tree, using `canonicalize(skill_dir)` as the base
1117→    // would silently accept writes to the symlink target.
1118→    let skills_root = skill_dir
1119→        .parent()
1120→        .ok_or_else(|| Error::message("invalid skill directory"))?;
1121→    let canonical_skills_root = tokio::fs::canonicalize(skills_root).await?;
1122→
1123→    // Reject a skill directory that is itself a symlink.
1124→    let skill_meta = tokio::fs::symlink_metadata(skill_dir).await?;
1125→    if skill_meta.file_type().is_symlink() {
1126→        return Err(Error::message("skill directory must not be a symlink"));
1127→    }
1128→
1129→    let canonical_base = tokio::fs::canonicalize(skill_dir).await?;
1130→    if !canonical_base.starts_with(&canonical_skills_root) {
1131→        return Err(Error::message("skill directory is outside the skills root"));
1132→    }
1133→
1134→    let mut written_paths: Vec<PathBuf> = Vec::new();
1135→
1136→    for file in files {
1137→        let target = skill_dir.join(&file.relative_path);
1138→        let parent = target
1139→            .parent()
1140→            .ok_or_else(|| Error::message("invalid file path"))?;
1141→
1142→        // Validate path ancestry *before* creating directories so a symlinked
1143→        // intermediate cannot cause out-of-tree directory creation.
1144→        validate_no_symlinks_in_ancestry(skill_dir, &file.relative_path).await?;
1145→
1146→        tokio::fs::create_dir_all(parent).await?;
1147→
1148→        let canonical_parent = tokio::fs::canonicalize(parent).await?;
1149→        if !canonical_parent.starts_with(&canonical_base) {
1150→            rollback_written_files(&written_paths).await;
1151→            return Err(Error::message(
1152→                "can only write inside the personal skill directory",
1153→            ));
1154→        }
1155→
1156→        if let Ok(metadata) = tokio::fs::symlink_metadata(&target).await {
1157→            if metadata.file_type().is_symlink() {
1158→                rollback_written_files(&written_paths).await;
1159→                return Err(Error::message(format!(
1160→                    "refusing to write through symlink '{}'",
1161→                    file.relative_path.display()
1162→                )));
1163→            }
1164→            if metadata.is_dir() {
1165→                rollback_written_files(&written_paths).await;
1166→                return Err(Error::message(format!(
1167→                    "target '{}' is a directory",
1168→                    file.relative_path.display()
1169→                )));
1170→            }
1171→        }
1172→
1173→        let Some(file_name) = file
1174→            .relative_path
1175→            .file_name()
1176→            .and_then(|value| value.to_str())
1177→        else {
1178→            rollback_written_files(&written_paths).await;
1179→            return Err(Error::message("invalid file name"));
1180→        };
1181→        let temp_name = format!(".{file_name}.moltis-tmp-{}", uuid::Uuid::new_v4());
1182→        let temp_path = parent.join(temp_name);
1183→
1184→        tokio::fs::write(&temp_path, &file.content).await?;
1185→        if let Err(error) = tokio::fs::rename(&temp_path, &target).await {
1186→            let _ = tokio::fs::remove_file(&temp_path).await;
1187→            rollback_written_files(&written_paths).await;
1188→            return Err(error.into());
1189→        }
1190→        written_paths.push(target);
1191→    }
1192→
1193→    Ok(())
1194→}
1195→
1196→/// Walk from `base` through the existing intermediate components of
1197→/// `relative_path` (excluding the final file component) and reject any
1198→/// symlink.  This prevents `create_dir_all` from following a symlinked
1199→/// intermediate and creating directories outside the skill tree.
1200→async fn validate_no_symlinks_in_ancestry(base: &Path, relative_path: &Path) -> crate::Result<()> {
1201→    let components: Vec<_> = relative_path.components().collect();
1202→    // Only check parent components — the last component is the file itself.
1203→    let parent_components = components.len().saturating_sub(1);
1204→    let mut current = base.to_path_buf();
1205→    for component in components.iter().take(parent_components) {
1206→        if let Component::Normal(segment) = component {
1207→            current.push(segment);
1208→            match tokio::fs::symlink_metadata(&current).await {
1209→                Ok(meta) if meta.file_type().is_symlink() => {
1210→                    return Err(Error::message(format!(
1211→                        "refusing to traverse symlink at '{}'",
1212→                        current.display()
1213→                    )));
1214→                },
1215→                Ok(_) => {},
1216→                // Path doesn't exist yet — safe to stop; create_dir_all will
1217→                // create it as a real directory.
1218→                Err(_) => break,
1219→            }
1220→        }
1221→    }
1222→    Ok(())
1223→}
1224→
1225→/// Best-effort removal of already-written files when a batch fails mid-way.
1226→async fn rollback_written_files(paths: &[PathBuf]) {
1227→    for path in paths.iter().rev() {
1228→        let _ = tokio::fs::remove_file(path).await;
1229→    }
1230→}
1231→
1232→fn audit_sidecar_file_write(data_dir: &Path, skill_name: &str, files: &[ValidatedSkillFile]) {
1233→    let dir = data_dir.join("logs");
1234→    let path = dir.join("security-audit.jsonl");
1235→    let now_ms = std::time::SystemTime::now()
1236→        .duration_since(std::time::UNIX_EPOCH)
1237→        .unwrap_or_default()
1238→        .as_millis() as u64;
1239→    let line = serde_json::json!({
1240→        "ts": now_ms,
1241→        "event": "skills.sidecar_files.write",
1242→        "details": {
1243→            "skill": skill_name,
1244→            "files": files.iter().map(|file| {
1245→                serde_json::json!({
1246→                    "path": file.relative_path.display().to_string(),
1247→                    "bytes": file.content.len(),
1248→                })
1249→            }).collect::<Vec<_>>(),
1250→        },
1251→    })
1252→    .to_string();
1253→
1254→    if let Err(err) = (|| -> std::io::Result<()> {
1255→        std::fs::create_dir_all(&dir)?;
1256→        let mut file = std::fs::OpenOptions::new()
1257→            .create(true)
1258→            .append(true)
1259→            .open(path)?;
1260→        use std::io::Write as _;
1261→        writeln!(file, "{line}")?;
1262→        Ok(())
1263→    })() {
1264→        tracing::warn!(
1265→            error = %err,
1266→            skill = skill_name,
1267→            "failed to write sidecar-file audit entry"
1268→        );
1269→    }
1270→}
1271→
1272→#[cfg(test)]
1273→mod tests;
