 38→    /// Build the default search paths rooted at an explicit workspace / data
 39→    /// directory.
 40→    ///
 41→    /// Prefer this over [`default_paths`](Self::default_paths) when the caller
 42→    /// already has a `data_dir` in hand (e.g. the gateway's `bootstrap` scope)
 43→    /// so the read and write sides stay consistent even if
 44→    /// `moltis_config::data_dir()` is ever reconfigured at runtime.
 45→    #[must_use]
 46→    pub fn default_paths_for(data_dir: &Path) -> Vec<(PathBuf, SkillSource)> {
 47→        vec![
 48→            (data_dir.join(".moltis/skills"), SkillSource::Project),
 49→            (data_dir.join("skills"), SkillSource::Personal),
 50→            (data_dir.join("installed-skills"), SkillSource::Registry),
 51→            (data_dir.join("installed-plugins"), SkillSource::Plugin),
 52→        ]
 53→    }
 54→}
