439→                        trusted: true,
440→                        enabled: true,
441→                    }],
442→                },
443→            ],
444→        };
445→        let manifest_path = tmp.path().join("skills-manifest.json");
446→        let store = ManifestStore::new(manifest_path);
447→        store.save(&manifest).unwrap();
448→
449→        // Can't call discover_registry directly (uses default_path), so
450→        // simulate the logic inline.
451→        let mut skills = Vec::new();
452→        for repo in &manifest.repos {
453→            for skill_state in &repo.skills {
454→                if !skill_state.enabled || !skill_state.trusted {
455→                    continue;
456→                }
457→                let skill_dir = install_dir.join(&skill_state.relative_path);
458→                match repo.format {
459→                    PluginFormat::Skill => {
460→                        let skill_md = skill_dir.join("SKILL.md");
461→                        if skill_md.is_file() {
462→                            let content = std::fs::read_to_string(&skill_md).unwrap();
463→                            let mut meta = parse::parse_metadata(&content, &skill_dir).unwrap();
464→                            meta.source = Some(SkillSource::Registry);
465→                            skills.push(meta);
466→                        }
467→                    },
468→                    _ => {
469→                        skills.push(SkillMetadata {
470→                            name: skill_state.name.clone(),
471→                            path: skill_dir,
472→                            source: Some(SkillSource::Plugin),
473→                            ..Default::default()
474→                        });
475→                    },
476→                }
477→            }
478→        }
479→
480→        assert_eq!(skills.len(), 2);
481→
482→        // SKILL.md repo gets full metadata with Registry source
483→        let skill = skills.iter().find(|s| s.name == "my-skill").unwrap();
484→        assert_eq!(skill.source, Some(SkillSource::Registry));
485→        assert_eq!(skill.description, "a native skill");
486→
487→        // Claude Code repo gets stub metadata with Plugin source
488→        let plugin = skills
489→            .iter()
490→            .find(|s| s.name == "test-plugin:helper")
491→            .unwrap();
492→        assert_eq!(plugin.source, Some(SkillSource::Plugin));
493→        assert!(plugin.description.is_empty());
494→    }
495→}
