253→/// Try to read and parse `_meta.json` from a skill directory.
254→/// Returns `None` if the file doesn't exist or can't be parsed.
255→pub fn read_meta_json(skill_dir: &Path) -> Option<SkillMetaJson> {
256→    let path = skill_dir.join("_meta.json");
257→    let content = std::fs::read_to_string(path).ok()?;
258→    serde_json::from_str(&content).ok()
259→}
260→
261→/// Split SKILL.md content at `---` delimiters into (frontmatter, body).
262→fn split_frontmatter(content: &str) -> Result<(String, String)> {
263→    let trimmed = content.trim_start();
264→    if !trimmed.starts_with("---") {
265→        return Err(Error::Parse(
266→            "SKILL.md must start with YAML frontmatter delimited by ---".into(),
267→        ));
268→    }
269→
270→    // Skip the opening ---
271→    let after_open = &trimmed[3..];
272→    let close_pos = after_open
273→        .find("\n---")
274→        .ok_or_else(|| Error::Parse("SKILL.md missing closing --- for frontmatter".into()))?;
275→
276→    let frontmatter = after_open[..close_pos].trim().to_string();
277→    let body = after_open[close_pos + 4..].trim().to_string();
278→    Ok((frontmatter, body))
279→}
280→
281→/// Tolerant variant of [`split_frontmatter`]: returns only the body after an
282→/// optional YAML frontmatter block. If the content doesn't start with a
283→/// `---` fence or the closing `---` is missing, returns the original content
284→/// unchanged.
285→///
286→/// Unlike `parse_skill`, this helper never errors and never validates the
287→/// frontmatter's schema — it's intended for consumers that just want a clean
288→/// markdown body without a full schema check (e.g. reading plugin-backed
289→/// skills whose frontmatter may follow a non-SKILL.md convention).
290→#[must_use]
291→pub fn strip_optional_frontmatter(content: &str) -> &str {
292→    let trimmed_start = content.trim_start();
293→    let Some(after_open) = trimmed_start.strip_prefix("---") else {
294→        return content;
295→    };
296→    let Some(close_pos) = after_open.find("\n---") else {
297→        return content;
298→    };
299→    // Advance past "\n---" and any trailing newline so the caller sees
300→    // clean markdown starting at the first real content line.
301→    let rest = &after_open[close_pos + 4..];
302→    rest.trim_start_matches(['\r', '\n'])
303→}
