 234→        if !skill_dir.exists() {
 235→            return Err(Error::message(format!(
 236→                "skill '{name}' does not exist; use create_skill first"
 237→            ))
 238→            .into());
 239→        }
 240→
 241→        let checkpoint = self
 242→            .checkpoints
 243→            .checkpoint_path(&skill_dir, "update_skill")
 244→            .await?;
 245→        let content = build_skill_md(name, description, body, &allowed_tools);
 246→        write_skill(&skill_dir, &content).await?;
 247→
 248→        Ok(json!({
 249→            "updated": true,
 250→            "path": skill_dir.display().to_string(),
 251→            "checkpointId": checkpoint.id,
 252→        }))
 253→    }
 254→}
