 340→/// Tool that reads a skill's body (and optionally a sidecar file) using the
 341→/// same discoverer that the `<available_skills>` prompt block was built from.
 342→///
 343→/// This is the read-side mirror of [`WriteSkillFilesTool`] and replaces the
 344→/// previous expectation that the model would use an external filesystem MCP
 345→/// server to load `SKILL.md` by absolute path.
 346→pub struct ReadSkillTool {
 347→    discoverer: Arc<dyn SkillDiscoverer>,
 348→}
 349→
 350→impl ReadSkillTool {
 351→    /// Construct a `ReadSkillTool` backed by the given discoverer.
 352→    ///
 353→    /// The discoverer should be the same one used to build the
 354→    /// `<available_skills>` prompt block so names listed there always resolve.
 355→    #[must_use]
 356→    pub fn new(discoverer: Arc<dyn SkillDiscoverer>) -> Self {
 357→        Self { discoverer }
 358→    }
 359→
 360→    /// Convenience constructor that uses
 361→    /// [`FsSkillDiscoverer::default_paths`](moltis_skills::discover::FsSkillDiscoverer::default_paths).
 362→    ///
 363→    /// Useful for tests and for call sites that already rely on the default
 364→    /// filesystem layout.
 365→    #[must_use]
 366→    pub fn with_default_paths() -> Self {
 367→        use moltis_skills::discover::FsSkillDiscoverer;
 368→        let discoverer = Arc::new(FsSkillDiscoverer::new(FsSkillDiscoverer::default_paths()));
 369→        Self { discoverer }
 370→    }
 371→}
 372→
 373→#[async_trait]
 374→impl AgentTool for ReadSkillTool {
 375→    fn name(&self) -> &str {
 376→        "read_skill"
 377→    }
 378→
 379→    fn description(&self) -> &str {
 380→        "Load a skill's full content or access its linked files (references, \
 381→         templates, assets, scripts). The primary call (with just 'name') \
 382→         returns the SKILL.md body plus a list of available sidecar files \
 383→         under references/, templates/, assets/, and scripts/. To read those, \
 384→         call again with the file_path argument \
 385→         (e.g. file_path=\"references/api.md\"). Nested file_paths such as \
 386→         \"references/subdir/deep.md\" are supported even if the listing only \
 387→         shows the first level. Binary files return a structured response \
 388→         with { is_binary: true, bytes }. Use the skill names listed in the \
 389→         <available_skills> system-prompt block."
 390→    }
 391→
 392→    fn parameters_schema(&self) -> Value {
 393→        json!({
 394→            "type": "object",
 395→            "required": ["name"],
 396→            "properties": {
 397→                "name": {
 398→                    "type": "string",
 399→                    "description": "Skill name (use the names from <available_skills>)"
 400→                },
 401→                "file_path": {
 402→                    "type": "string",
 403→                    "description": "Optional: relative path to a sidecar file inside the skill directory (e.g. 'references/api.md'). Omit to read the main SKILL.md body."
 404→                }
 405→            }
 406→        })
 407→    }
 408→
 409→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
 410→        let name = params
 411→            .get("name")
 412→            .and_then(|v| v.as_str())
 413→            .ok_or_else(|| Error::message("missing 'name'"))?;
 414→        let file_path = params.get("file_path").and_then(|v| v.as_str());
 415→
 416→        let skills = self.discoverer.discover().await?;
 417→        let meta = skills.iter().find(|s| s.name == name).ok_or_else(|| {
 418→            let available: Vec<&str> = skills.iter().map(|s| s.name.as_str()).collect();
 419→            let hint = if available.is_empty() {
 420→                "no skills are currently available".to_string()
 421→            } else {
 422→                format!("available skills: {}", available.join(", "))
 423→            };
 424→            Error::message(format!(
 425→                "skill '{name}' not found ({hint}). Use one of the names listed \
 426→                 in <available_skills>."
 427→            ))
 428→        })?;
 429→
 430→        if let Some(rel) = file_path {
 431→            // Plugin-backed skills can be a single `.md` file rather than
 432→            // a directory containing SKILL.md. Reject sidecar requests on
 433→            // such skills with a clear error — otherwise `read_sidecar`
 434→            // would canonicalise the `.md` file and join the relative
 435→            // path, producing nonsense like `/plugin/demo.md/references/api.md`
 436→            // that would fail with an opaque I/O error.
 437→            if meta.source.as_ref() == Some(&SkillSource::Plugin)
 438→                && tokio::fs::metadata(&meta.path)
 439→                    .await
 440→                    .map(|m| m.is_file())
 441→                    .unwrap_or(false)
 442→            {
 443→                return Err(Error::message(format!(
 444→                    "plugin skill '{name}' is a single .md file and has no \
 445→                     sidecar directory; omit file_path to read the body"
 446→                ))
 447→                .into());
 448→            }
 449→            return read_sidecar(name, &meta.path, rel).await;
 450→        }
 451→
 452→        read_primary(name, meta).await
 453→    }
 454→}
 455→
 456→/// Read the main SKILL.md body (or the plugin's `.md` file) plus the list of
 457→/// sidecar files available in `references/`, `templates/`, `assets/`, and
 458→/// `scripts/`. The response also surfaces frontmatter metadata fields
 459→/// (`license`, `homepage`, `compatibility`, `allowed_tools`, `display_name`)
 460→/// so the agent can make informed activation decisions without a second call.
 461→async fn read_primary(
 462→    name: &str,
 463→    meta: &moltis_skills::types::SkillMetadata,
 464→) -> anyhow::Result<Value> {
 465→    let is_plugin = meta.source.as_ref() == Some(&SkillSource::Plugin);
 466→
 467→    // Reject a symlinked skill root the same way `read_sidecar` and
 468→    // `write_sidecar_files` do. Without this guard, a symlink like
 469→    // `~/.moltis/skills/malicious -> /etc` would canonicalise silently
 470→    // and the rest of the read path would serve whatever the target
 471→    // resolves to. Defence in depth: the discoverer should not hand us a
 472→    // symlinked root, but the tool enforces the invariant regardless.
 473→    match tokio::fs::symlink_metadata(&meta.path).await {
 474→        Ok(m) if m.file_type().is_symlink() => {
 475→            return Err(
 476→                Error::message(format!("skill '{name}' directory must not be a symlink")).into(),
 477→            );
 478→        },
 479→        Ok(_) => {},
 480→        Err(e) => {
 481→            return Err(Error::message(format!("skill '{name}' path not accessible: {e}")).into());
 482→        },
 483→    }
 484→
 485→    // Detect whether a plugin-backed skill is a single `.md` file (rather
 486→    // than a SKILL.md-in-a-directory) via async metadata so the read path
 487→    // stays fully non-blocking — no synchronous `Path::is_file` inside an
 488→    // async function.
 489→    let plugin_as_file = is_plugin
 490→        && tokio::fs::metadata(&meta.path)
 491→            .await
 492→            .map(|m| m.is_file())
 493→            .unwrap_or(false);
 494→
 495→    // Plugin skills can be backed by a single `.md` file rather than a
 496→    // directory containing SKILL.md (see `prompt_gen.rs`). Handle both shapes.
 497→    let (loaded_meta, body, linked_files, effective_dir) = if plugin_as_file {
 498→        // Size check *before* reading the whole file so we never buffer a
 499→        // multi-megabyte `.md` into memory only to reject it. Mirrors the
 500→        // defence-in-depth posture `read_sidecar` uses for sidecar files.
 501→        let file_meta = tokio::fs::metadata(&meta.path).await.map_err(|e| {
 502→            Error::message(format!(
 503→                "failed to stat plugin skill '{name}' at {}: {e}",
 504→                meta.path.display()
 505→            ))
 506→        })?;
 507→        if file_meta.len() > MAX_SKILL_BODY_BYTES as u64 {
 508→            return Err(Error::message(format!(
 509→                "plugin skill '{name}' body exceeds maximum size of \
 510→                 {MAX_SKILL_BODY_BYTES} bytes ({} bytes on disk)",
 511→                file_meta.len()
 512→            ))
 513→            .into());
 514→        }
 515→        let raw = tokio::fs::read_to_string(&meta.path).await.map_err(|e| {
 516→            Error::message(format!(
 517→                "failed to read plugin skill '{name}' at {}: {e}",
 518→                meta.path.display()
 519→            ))
 520→        })?;
 521→        // Strip any optional YAML frontmatter so the model sees clean
 522→        // markdown — without this, plugin-backed skills that follow the
 523→        // SKILL.md format return `---\nname: ...\n---` noise in the body.
 524→        // Mirrors what `load_skill_from_path` does for directory-backed
 525→        // skills via `parse::parse_skill`.
 526→        let body = moltis_skills::parse::strip_optional_frontmatter(&raw).to_string();
 527→        let effective_dir = meta
 528→            .path
 529→            .parent()
 530→            .map(Path::to_path_buf)
 531→            .unwrap_or_else(|| meta.path.clone());
 532→        // Plugin .md files don't carry full frontmatter in the discovered
 533→        // metadata — fall back to the discoverer's stub metadata.
 534→        (meta.clone(), body, Vec::new(), effective_dir)
 535→    } else {
 536→        let canonical_skill_dir = tokio::fs::canonicalize(&meta.path).await.map_err(|e| {
 537→            Error::message(format!("skill directory not accessible for '{name}': {e}"))
 538→        })?;
 539→
 540→        // Apply the same defensive ceiling to directory-backed SKILL.md
 541→        // files so the plugin and directory paths have symmetric limits.
 542→        let skill_md_path = canonical_skill_dir.join("SKILL.md");
 543→        if let Ok(m) = tokio::fs::metadata(&skill_md_path).await
 544→            && m.len() > MAX_SKILL_BODY_BYTES as u64
 545→        {
 546→            return Err(Error::message(format!(
 547→                "skill '{name}' SKILL.md exceeds maximum size of \
 548→                 {MAX_SKILL_BODY_BYTES} bytes ({} bytes on disk)",
 549→                m.len()
 550→            ))
 551→            .into());
 552→        }
 553→
 554→        let content = moltis_skills::registry::load_skill_from_path(&canonical_skill_dir)
 555→            .await
 556→            .map_err(|e| Error::message(format!("failed to load skill '{name}': {e}")))?;
 557→        let linked = list_skill_sidecar_files(&canonical_skill_dir).await?;
 558→        (content.metadata, content.body, linked, canonical_skill_dir)
 559→    };
 560→
 561→    // Warn on injection patterns (do not block).
 562→    let hits = moltis_skills::safety::scan_skill_body(name, &body);
 563→    if !hits.is_empty() {
 564→        tracing::warn!(
 565→            skill = %name,
 566→            patterns = ?hits,
 567→            "skill body contains potential prompt-injection patterns"
 568→        );
 569→    }
 570→
 571→    let source_label = match meta.source.as_ref() {
 572→        Some(SkillSource::Project) => "project",
 573→        Some(SkillSource::Personal) => "personal",
 574→        Some(SkillSource::Plugin) => "plugin",
 575→        Some(SkillSource::Registry) => "registry",
 576→        None => "unknown",
 577→    };
 578→
 579→    // Build the response as a Map directly to avoid the
 580→    // `as_object_mut().expect()` pattern that workspace clippy lints on.
 581→    // Optional metadata fields are only included when set so the agent
 582→    // doesn't wade through empty keys.
 583→    let mut response = serde_json::Map::new();
 584→    response.insert("name".into(), json!(name));
 585→    response.insert("description".into(), json!(loaded_meta.description));
 586→    response.insert("source".into(), json!(source_label));
 587→    response.insert("body".into(), json!(body));
 588→    response.insert("bytes".into(), json!(body.len()));
 589→    response.insert(
 590→        "skill_dir_name".into(),
 591→        json!(
 592→            effective_dir
 593→                .file_name()
 594→                .and_then(|n| n.to_str())
 595→                .unwrap_or("")
 596→        ),
 597→    );
 598→
 599→    if let Some(display_name) = &loaded_meta.display_name {
 600→        response.insert("display_name".into(), json!(display_name));
 601→    }
 602→    if let Some(license) = &loaded_meta.license {
 603→        response.insert("license".into(), json!(license));
 604→    }
 605→    if let Some(homepage) = &loaded_meta.homepage {
 606→        response.insert("homepage".into(), json!(homepage));
 607→    }
 608→    if let Some(compatibility) = &loaded_meta.compatibility {
 609→        response.insert("compatibility".into(), json!(compatibility));
 610→    }
 611→    if !loaded_meta.allowed_tools.is_empty() {
 612→        response.insert("allowed_tools".into(), json!(loaded_meta.allowed_tools));
 613→    }
 614→    if !linked_files.is_empty() {
 615→        response.insert(
 616→            "usage_hint".into(),
 617→            json!(
 618→                "To view a linked file, call read_skill again with file_path \
 619→                 set to one of the paths in linked_files (e.g. \
 620→                 file_path=\"references/api.md\"). Nested paths inside those \
 621→                 directories are also supported."
 622→            ),
 623→        );
 624→    }
 625→    // `linked_files` goes last so tools that pretty-print the response
 626→    // surface metadata first.
 627→    response.insert("linked_files".into(), json!(linked_files));
 628→
 629→    Ok(Value::Object(response))
 630→}
 631→
 632→/// Read a single sidecar file inside a skill directory.
 633→///
 634→/// Supports arbitrary-depth `Component::Normal`-only relative paths (e.g.
 635→/// `references/subdir/deep.md`). Binary files return a structured
 636→/// `{ is_binary: true, bytes }` response instead of failing on UTF-8 decode.
 637→/// If the file doesn't exist, returns a helpful listing of the sidecar files
 638→/// that do exist under this skill.
 639→async fn read_sidecar(name: &str, skill_dir: &Path, rel: &str) -> anyhow::Result<Value> {
 640→    let relative = normalize_relative_skill_file_path(rel)?;
 641→
 642→    // Reject a symlinked skill directory to stay consistent with
 643→    // `write_sidecar_files`. Without this, a symlinked skill root
 644→    // (e.g. `~/.moltis/skills/malicious -> /etc`) would pass the later
 645→    // canonical-prefix check because `canonicalize` resolves the symlink
 646→    // and the subsequent `starts_with` comparison succeeds against the
 647→    // resolved target.
 648→    match tokio::fs::symlink_metadata(skill_dir).await {
 649→        Ok(meta) if meta.file_type().is_symlink() => {
 650→            return Err(
 651→                Error::message(format!("skill '{name}' directory must not be a symlink")).into(),
 652→            );
 653→        },
 654→        Ok(_) => {},
 655→        Err(e) => {
 656→            return Err(Error::message(format!(
 657→                "skill directory not accessible for '{name}': {e}"
 658→            ))
 659→            .into());
 660→        },
 661→    }
 662→
 663→    let canonical_skill_dir = tokio::fs::canonicalize(skill_dir)
 664→        .await
 665→        .map_err(|e| Error::message(format!("skill directory not accessible for '{name}': {e}")))?;
 666→
 667→    let target = canonical_skill_dir.join(&relative);
 668→
 669→    // Check existence before canonicalising so we can return a helpful
 670→    // listing instead of an opaque I/O error when the file is missing.
 671→    match tokio::fs::symlink_metadata(&target).await {
 672→        Ok(_) => {},
 673→        Err(err) if err.kind() == std::io::ErrorKind::NotFound => {
 674→            let available = list_skill_sidecar_files(&canonical_skill_dir).await?;
 675→            return Err(Error::message(format!(
 676→                "sidecar file '{}' not found in skill '{name}'. \
 677→                 Available sidecar files: {}",
 678→                relative.display(),
 679→                if available.is_empty() {
 680→                    "(none)".to_string()
 681→                } else {
 682→                    available
 683→                        .iter()
 684→                        .filter_map(|v| v.get("path").and_then(|p| p.as_str()))
 685→                        .collect::<Vec<_>>()
 686→                        .join(", ")
 687→                }
 688→            ))
 689→            .into());
 690→        },
 691→        Err(e) => {
 692→            return Err(Error::message(format!(
 693→                "sidecar file '{}' not accessible: {e}",
 694→                relative.display()
 695→            ))
 696→            .into());
 697→        },
 698→    }
 699→
 700→    let canonical_target = tokio::fs::canonicalize(&target).await.map_err(|e| {
 701→        Error::message(format!(
 702→            "sidecar file '{}' not accessible: {e}",
 703→            relative.display()
 704→        ))
 705→    })?;
 706→
 707→    if !canonical_target.starts_with(&canonical_skill_dir) {
 708→        return Err(Error::message(format!(
 709→            "sidecar file '{}' is outside the skill directory",
 710→            relative.display()
 711→        ))
 712→        .into());
 713→    }
 714→
 715→    let metadata = tokio::fs::metadata(&canonical_target).await?;
 716→    if !metadata.is_file() {
 717→        return Err(Error::message(format!(
 718→            "sidecar path '{}' is not a regular file",
 719→            relative.display()
 720→        ))
 721→        .into());
 722→    }
 723→    if metadata.len() > MAX_SIDECAR_FILE_BYTES as u64 {
 724→        return Err(Error::message(format!(
 725→            "sidecar file '{}' exceeds maximum size of {MAX_SIDECAR_FILE_BYTES} bytes",
 726→            relative.display()
 727→        ))
 728→        .into());
 729→    }
 730→
 731→    // Try UTF-8; fall back to a structured "binary" response on decode
 732→    // failure (mirrors hermes-agent's `skill_view` behavior).
 733→    let raw = tokio::fs::read(&canonical_target).await.map_err(|e| {
 734→        Error::message(format!(
 735→            "failed to read sidecar file '{}': {e}",
 736→            relative.display()
 737→        ))
 738→    })?;
 739→
 740→    match std::str::from_utf8(&raw) {
 741→        Ok(text) => Ok(json!({
 742→            "name": name,
 743→            "file_path": relative.display().to_string(),
 744→            "bytes": metadata.len(),
 745→            "content": text,
 746→            "is_binary": false,
 747→        })),
 748→        Err(_) => {
 749→            let file_type = canonical_target
 750→                .extension()
 751→                .and_then(|e| e.to_str())
 752→                .map(|s| format!(".{s}"))
 753→                .unwrap_or_default();
 754→            Ok(json!({
 755→                "name": name,
 756→                "file_path": relative.display().to_string(),
 757→                "bytes": metadata.len(),
 758→                "is_binary": true,
 759→                "file_type": file_type,
 760→                "note": format!(
 761→                    "Binary file ({} bytes). Contents omitted — the model \
 762→                     cannot consume binary data directly.",
 763→                    metadata.len()
 764→                ),
 765→            }))
 766→        },
 767→    }
 768→}
 769→
 770→/// Sidecar subdirectories that are walked for the primary-read linked-files
 771→/// listing. Re-exported from [`moltis_skills::SIDECAR_SUBDIRS`] so the prompt
 772→/// generator and the read-side walker stay in lockstep — adding a new entry
 773→/// in the skills crate automatically propagates to both the activation
 774→/// instruction and this walker, eliminating a whole class of drift bugs.
 775→const SIDECAR_SUBDIRS: &[&str] = moltis_skills::SIDECAR_SUBDIRS;
 776→
 777→/// Entry returned by [`list_skill_sidecar_files`]. Sorted-for-determinism and
 778→/// kept as a typed struct so both the primary read path and the sidecar
 779→/// "file not found" error path can reuse it.
 780→#[derive(Debug, Clone)]
 781→struct SidecarEntry {
 782→    /// Path relative to the skill directory, e.g. `references/api.md`.
 783→    relative_path: String,
 784→    bytes: u64,
 785→}
 786→
 787→impl From<&SidecarEntry> for Value {
 788→    fn from(entry: &SidecarEntry) -> Self {
 789→        json!({
 790→            "path": entry.relative_path,
 791→            "bytes": entry.bytes,
 792→        })
 793→    }
 794→}
 795→
 796→/// One-level-deep walk of `<skill_dir>/{references,templates,assets,scripts}`.
 797→///
 798→/// Returns a sorted (by relative path) list of entries, capped at
 799→/// [`MAX_SIDECAR_FILES_PER_CALL`]. Directory entries, symlinks, hidden files
 800→/// (dotfiles), and unreadable entries are skipped silently so the listing
 801→/// only shows real in-skill files the agent can actually consume.
 802→async fn list_skill_sidecar_files(skill_dir: &Path) -> crate::Result<Vec<Value>> {
 803→    let mut entries = collect_sidecar_entries(skill_dir).await?;
 804→    // Sort for deterministic output — makes tests stable and the agent's
 805→    // reasoning traces reproducible across runs.
 806→    entries.sort_by(|a, b| a.relative_path.cmp(&b.relative_path));
 807→    Ok(entries.iter().map(Value::from).collect())
 808→}
