 810→async fn collect_sidecar_entries(skill_dir: &Path) -> crate::Result<Vec<SidecarEntry>> {
 811→    let mut out: Vec<SidecarEntry> = Vec::new();
 812→
 813→    for sub in SIDECAR_SUBDIRS {
 814→        // Stop early if the global cap is already exhausted so we don't
 815→        // over-report, but *do* enter each subdir as long as it has free
 816→        // budget — the per-subdir cap below guarantees every populated
 817→        // subdirectory gets its fair share even when one dir contains
 818→        // hundreds of files.
 819→        if out.len() >= MAX_SIDECAR_FILES_PER_CALL {
 820→            break;
 821→        }
 822→        let dir = skill_dir.join(sub);
 823→        // Use `tokio::fs::read_dir` directly and treat a missing or
 824→        // unreadable subdirectory as "no entries" — avoids a synchronous
 825→        // `Path::is_dir()` stat inside this async function.
 826→        let mut entries = match tokio::fs::read_dir(&dir).await {
 827→            Ok(e) => e,
 828→            Err(_) => continue,
 829→        };
 830→        let mut this_subdir = 0usize;
 831→        while let Some(entry) = entries.next_entry().await? {
 832→            // Enforce both the per-subdir cap (so `references/` can't
 833→            // swallow the entire listing and hide `templates/` or
 834→            // `scripts/`) and the global cap (so a pathological skill
 835→            // can't return thousands of entries).
 836→            if this_subdir >= MAX_SIDECAR_FILES_PER_SUBDIR
 837→                || out.len() >= MAX_SIDECAR_FILES_PER_CALL
 838→            {
 839→                break;
 840→            }
 841→            // Reject symlinks so the listing only shows real in-skill files.
 842→            let file_type = match entry.file_type().await {
 843→                Ok(ft) => ft,
 844→                Err(_) => continue,
 845→            };
 846→            if !file_type.is_file() {
 847→                continue;
 848→            }
 849→            let meta = match entry.metadata().await {
 850→                Ok(m) => m,
 851→                Err(_) => continue,
 852→            };
 853→            let file_name = match entry.file_name().into_string() {
 854→                Ok(name) => name,
 855→                Err(_) => continue,
 856→            };
 857→            if file_name.starts_with('.') {
 858→                continue;
 859→            }
 860→            out.push(SidecarEntry {
 861→                relative_path: format!("{sub}/{file_name}"),
 862→                bytes: meta.len(),
 863→            });
 864→            this_subdir += 1;
 865→        }
 866→    }
 867→
 868→    Ok(out)
 869→}
