  1→//! Static asset serving with three-tier resolution:
  2→//!
  3→//! 1. **Dev filesystem** — `MOLTIS_ASSETS_DIR` env var or auto-detected from
  4→//!    the crate source tree when running via `cargo run`.
  5→//! 2. **External share dir** — `share_dir()/web/` for packaged deployments
  6→//!    (Debian, RPM, Docker) where assets live outside the binary.
  7→//! 3. **Embedded fallback** — `include_dir!` compiled into the binary (only
  8→//!    available when the `embedded-assets` feature is enabled).
  9→
 10→use std::{
 11→    path::{Component, Path as FsPath, PathBuf},
 12→    sync::LazyLock,
 13→};
 14→
 15→#[cfg(feature = "embedded-assets")]
 16→use tracing::warn;
 17→use {
 18→    axum::{extract::Path, http::StatusCode, response::IntoResponse},
 19→    serde::Serialize,
 20→    tracing::info,
 21→};
 22→
 23→// ── Embedded assets (feature-gated) ─────────────────────────────────────────
 24→
 25→#[cfg(feature = "embedded-assets")]
 26→static ASSETS: include_dir::Dir = include_dir::include_dir!("$CARGO_MANIFEST_DIR/src/assets");
 27→
 28→// Fail compilation with a clear message if style.css hasn't been generated.
 29→// Run `just build-css` (or `cd crates/web/ui && ./build.sh`) to generate it.
 30→#[cfg(feature = "embedded-assets")]
 31→const _: &str = include_str!("assets/css/style.css");
 32→
 33→// ── Asset source resolution ─────────────────────────────────────────────────
 34→
 35→/// Resolved asset source, checked once at startup.
 36→enum AssetSource {
 37→    /// Filesystem directory (dev mode or `MOLTIS_ASSETS_DIR`).
 38→    Filesystem(PathBuf),
 39→    /// External share directory (`share_dir()/web/`).
 40→    External(PathBuf),
 41→    /// Embedded in binary (feature `embedded-assets`).
 42→    #[cfg(feature = "embedded-assets")]
 43→    Embedded,
 44→    /// No assets available (embedded-assets feature disabled, no external dir).
 45→    #[cfg(not(feature = "embedded-assets"))]
 46→    Unavailable,
 47→}
 48→
 49→struct AssetState {
 50→    source: AssetSource,
 51→    hash: String,
 52→    fallback_reason: Option<&'static str>,
 53→    #[cfg(feature = "embedded-assets")]
 54→    external_hash: Option<String>,
 55→    #[cfg(feature = "embedded-assets")]
 56→    embedded_hash: Option<String>,
 57→}
 58→
 59→#[derive(Serialize)]
 60→#[serde(rename_all = "camelCase")]
 61→struct AssetVersionInfo<'a> {
 62→    moltis_version: &'static str,
 63→    asset_hash: &'a str,
 64→    asset_source: &'static str,
 65→    #[serde(skip_serializing_if = "Option::is_none")]
 66→    fallback_reason: Option<&'static str>,
 67→    #[cfg(feature = "embedded-assets")]
 68→    #[serde(skip_serializing_if = "Option::is_none")]
 69→    external_asset_hash: Option<&'a str>,
 70→    #[cfg(feature = "embedded-assets")]
 71→    #[serde(skip_serializing_if = "Option::is_none")]
 72→    embedded_asset_hash: Option<&'a str>,
 73→}
 74→
 75→impl AssetState {
 76→    fn from_source(source: AssetSource) -> Self {
 77→        let hash = hash_for_source(&source);
 78→        Self {
 79→            source,
 80→            hash,
 81→            fallback_reason: None,
 82→            #[cfg(feature = "embedded-assets")]
 83→            external_hash: None,
 84→            #[cfg(feature = "embedded-assets")]
 85→            embedded_hash: None,
 86→        }
 87→    }
 88→
 89→    #[cfg(feature = "embedded-assets")]
 90→    fn embedded_fallback(
 91→        embedded_hash: String,
 92→        external_hash: String,
 93→        fallback_reason: &'static str,
 94→    ) -> Self {
 95→        Self {
 96→            source: AssetSource::Embedded,
 97→            hash: embedded_hash.clone(),
 98→            fallback_reason: Some(fallback_reason),
 99→            external_hash: Some(external_hash),
100→            embedded_hash: Some(embedded_hash),
101→        }
102→    }
103→
104→    fn source_name(&self) -> &'static str {
105→        match &self.source {
106→            AssetSource::Filesystem(_) => "filesystem",
107→            AssetSource::External(_) => "external",
108→            #[cfg(feature = "embedded-assets")]
109→            AssetSource::Embedded => "embedded",
110→            #[cfg(not(feature = "embedded-assets"))]
111→            AssetSource::Unavailable => "unavailable",
112→        }
113→    }
114→
115→    fn version_info(&self) -> AssetVersionInfo<'_> {
116→        AssetVersionInfo {
117→            moltis_version: moltis_config::VERSION,
118→            asset_hash: &self.hash,
119→            asset_source: self.source_name(),
120→            fallback_reason: self.fallback_reason,
121→            #[cfg(feature = "embedded-assets")]
122→            external_asset_hash: self.external_hash.as_deref(),
123→            #[cfg(feature = "embedded-assets")]
124→            embedded_asset_hash: self.embedded_hash.as_deref(),
125→        }
126→    }
127→}
128→
129→static ASSET_STATE: LazyLock<AssetState> = LazyLock::new(resolve_asset_state);
130→
131→fn resolve_asset_state() -> AssetState {
132→    // 1. Explicit env var
133→    let explicit_dir = std::env::var("MOLTIS_ASSETS_DIR").ok().map(PathBuf::from);
134→
135→    // 2. Auto-detect cargo source tree (dev mode)
136→    let cargo_dir = Some(PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("src/assets"));
137→
138→    // 3. External share directory
139→    resolve_asset_state_with_paths(explicit_dir, cargo_dir, moltis_config::share_dir())
140→}
141→
142→fn resolve_asset_state_with_paths(
143→    explicit_dir: Option<PathBuf>,
144→    cargo_dir: Option<PathBuf>,
145→    share_dir: Option<PathBuf>,
146→) -> AssetState {
147→    if let Some(dir) = explicit_dir.filter(|dir| dir.is_dir()) {
148→        info!("Serving assets from filesystem: {}", dir.display());
149→        return AssetState::from_source(AssetSource::Filesystem(dir));
150→    }
151→
152→    if let Some(dir) = cargo_dir.filter(|dir| dir.is_dir()) {
153→        info!("Serving assets from filesystem: {}", dir.display());
154→        return AssetState::from_source(AssetSource::Filesystem(dir));
155→    }
156→
157→    if let Some(share) = share_dir {
158→        let web_dir = share.join("web");
159→        if web_dir.is_dir() {
160→            #[cfg(feature = "embedded-assets")]
161→            {
162→                let external_hash = hash_filesystem_dir(&web_dir);
163→                let embedded_hash = hash_embedded_assets();
164→                if external_hash == embedded_hash {
165→                    info!(
166→                        "Serving assets from external share dir: {}",
167→                        web_dir.display()
168→                    );
169→                    return AssetState {
170→                        source: AssetSource::External(web_dir),
171→                        hash: external_hash.clone(),
172→                        fallback_reason: None,
173→                        external_hash: Some(external_hash),
174→                        embedded_hash: Some(embedded_hash),
175→                    };
176→                }
177→
178→                warn!(
179→                    external_dir = %web_dir.display(),
180→                    external_hash = %external_hash,
181→                    embedded_hash = %embedded_hash,
182→                    "External web assets differ from the embedded UI, serving embedded assets instead"
183→                );
184→                return AssetState::embedded_fallback(
185→                    embedded_hash,
186→                    external_hash,
187→                    "external-assets-mismatch",
188→                );
189→            }
190→
191→            #[cfg(not(feature = "embedded-assets"))]
192→            {
193→                info!(
194→                    "Serving assets from external share dir: {}",
195→                    web_dir.display()
196→                );
197→                return AssetState::from_source(AssetSource::External(web_dir));
198→            }
199→        }
200→    }
201→
202→    // 4. Embedded fallback (or unavailable)
203→    #[cfg(feature = "embedded-assets")]
204→    {
205→        info!("Serving assets from embedded binary");
206→        AssetState::from_source(AssetSource::Embedded)
207→    }
208→    #[cfg(not(feature = "embedded-assets"))]
209→    {
210→        info!("No asset source available (embedded-assets feature disabled)");
211→        AssetState::from_source(AssetSource::Unavailable)
212→    }
213→}
214→
215→/// Whether we're serving from the filesystem (dev mode) or embedded/external (release).
216→pub(crate) fn is_dev_assets() -> bool {
217→    matches!(&ASSET_STATE.source, AssetSource::Filesystem(_))
218→}
219→
220→/// Compute a short content hash of all assets for cache-busting versioned URLs.
221→pub(crate) fn asset_content_hash() -> String {
222→    ASSET_STATE.hash.clone()
223→}
224→
225→fn hash_for_source(source: &AssetSource) -> String {
226→    match source {
227→        AssetSource::Filesystem(dir) | AssetSource::External(dir) => hash_filesystem_dir(dir),
228→        #[cfg(feature = "embedded-assets")]
229→        AssetSource::Embedded => hash_embedded_assets(),
230→        #[cfg(not(feature = "embedded-assets"))]
231→        AssetSource::Unavailable => String::new(),
232→    }
233→}
234→
235→fn hash_filesystem_dir(dir: &FsPath) -> String {
236→    let mut files = std::collections::BTreeMap::new();
237→    walk_dir_for_hash(dir, dir, &mut files);
238→    hash_file_map(
239→        files
240→            .iter()
241→            .map(|(path, bytes)| (path.as_str(), bytes.as_slice())),
242→    )
243→}
244→
245→#[cfg(feature = "embedded-assets")]
246→fn hash_embedded_assets() -> String {
247→    let mut files = std::collections::BTreeMap::new();
248→    let mut stack: Vec<&include_dir::Dir<'_>> = vec![&ASSETS];
249→    while let Some(dir) = stack.pop() {
250→        for file in dir.files() {
251→            files.insert(file.path().display().to_string(), file.contents());
252→        }
253→        for sub in dir.dirs() {
254→            stack.push(sub);
255→        }
256→    }
257→    hash_file_map(files.iter().map(|(path, bytes)| (path.as_str(), *bytes)))
258→}
259→
260→fn hash_file_map<'a>(files: impl IntoIterator<Item = (&'a str, &'a [u8])>) -> String {
261→    use std::hash::Hasher;
262→
263→    let mut hasher = std::hash::DefaultHasher::new();
264→    for (path, contents) in files {
265→        hasher.write(path.as_bytes());
266→        hasher.write(contents);
267→    }
268→    format!("{:016x}", hasher.finish())
269→}
270→
271→/// Walk a filesystem directory for hashing, storing (relative_path, file_bytes)
272→/// pairs sorted by path.
273→fn walk_dir_for_hash(
274→    base: &FsPath,
275→    dir: &FsPath,
276→    out: &mut std::collections::BTreeMap<String, Vec<u8>>,
277→) {
278→    let Ok(entries) = std::fs::read_dir(dir) else {
279→        return;
280→    };
281→    for entry in entries.flatten() {
282→        let path = entry.path();
283→        if path.is_dir() {
284→            walk_dir_for_hash(base, &path, out);
285→        } else if let Ok(bytes) = std::fs::read(&path) {
286→            let rel = path
287→                .strip_prefix(base)
288→                .unwrap_or(&path)
289→                .display()
290→                .to_string();
291→            out.insert(rel, bytes);
292→        }
293→    }
294→}
295→
296→fn mime_for_path(path: &str) -> &'static str {
297→    match path.rsplit('.').next().unwrap_or("") {
298→        "css" => "text/css; charset=utf-8",
299→        "js" => "application/javascript; charset=utf-8",
300→        "mjs" => "application/javascript; charset=utf-8",
301→        "html" => "text/html; charset=utf-8",
302→        "svg" => "image/svg+xml",
303→        "png" => "image/png",
304→        "ico" => "image/x-icon",
305→        "json" => "application/json",
306→        "woff2" => "font/woff2",
307→        "woff" => "font/woff",
308→        _ => "application/octet-stream",
309→    }
310→}
311→
312→/// Read a file from a filesystem directory with path-traversal protection.
313→fn read_from_dir(dir: &std::path::Path, path: &str) -> Option<Vec<u8>> {
314→    let rel = FsPath::new(path);
315→    if rel.is_absolute() {
316→        return None;
317→    }
318→
319→    if !rel
320→        .components()
321→        .all(|component| matches!(component, Component::Normal(_)))
322→    {
323→        return None;
324→    }
325→
326→    std::fs::read(dir.join(rel)).ok()
327→}
328→
329→/// Read an asset file using three-tier resolution.
330→fn read_asset(path: &str) -> Option<Vec<u8>> {
331→    if path == "version.json" {
332→        return serde_json::to_vec(&ASSET_STATE.version_info()).ok();
333→    }
334→
335→    match &ASSET_STATE.source {
336→        AssetSource::Filesystem(dir) | AssetSource::External(dir) => read_from_dir(dir, path),
337→        #[cfg(feature = "embedded-assets")]
338→        AssetSource::Embedded => ASSETS.get_file(path).map(|f| f.contents().to_vec()),
339→        #[cfg(not(feature = "embedded-assets"))]
340→        AssetSource::Unavailable => None,
341→    }
342→}
343→
344→/// Read raw asset bytes by path. Used by `share_render.rs` for the favicon.
345→pub fn read_asset_bytes(path: &str) -> Option<Vec<u8>> {
346→    read_asset(path)
347→}
348→
349→/// Versioned assets: `/assets/v/<hash>/path` — immutable, cached forever.
350→pub async fn versioned_asset_handler(
351→    Path((_version, path)): Path<(String, String)>,
352→) -> impl IntoResponse {
353→    let cache = if is_dev_assets() {
354→        "no-cache, no-store"
355→    } else {
356→        "public, max-age=31536000, immutable"
357→    };
358→    serve_asset(&path, cache)
359→}
360→
361→/// Unversioned assets: `/assets/path` — always revalidate.
362→pub async fn asset_handler(Path(path): Path<String>) -> impl IntoResponse {
363→    let cache = if is_dev_assets() {
364→        "no-cache, no-store"
365→    } else {
366→        "no-cache"
367→    };
368→    serve_asset(&path, cache)
369→}
370→
371→/// PWA manifest: `/manifest.json` — served from assets root.
372→pub async fn manifest_handler() -> impl IntoResponse {
373→    serve_asset("manifest.json", "no-cache")
374→}
375→
376→/// Service worker: `/sw.js` — served from assets root, no-cache for updates.
377→pub async fn service_worker_handler() -> impl IntoResponse {
378→    serve_asset("sw.js", "no-cache")
379→}
380→
381→fn serve_asset(path: &str, cache_control: &'static str) -> axum::response::Response {
382→    match read_asset(path) {
383→        Some(body) => {
384→            let mut response = (
385→                StatusCode::OK,
386→                [
387→                    ("content-type", mime_for_path(path)),
388→                    ("cache-control", cache_control),
389→                    ("x-content-type-options", "nosniff"),
390→                ],
391→                body,
392→            )
393→                .into_response();
394→
395→            // Harden SVG delivery against script execution when user-controlled
396→            // SVGs are ever introduced. Static first-party SVGs continue to render.
397→            if path.rsplit('.').next().unwrap_or("") == "svg" {
398→                response.headers_mut().insert(
399→                    axum::http::header::CONTENT_SECURITY_POLICY,
400→                    axum::http::HeaderValue::from_static(
401→                        "default-src 'none'; img-src 'self' data:; style-src 'none'; script-src 'none'; object-src 'none'; frame-ancestors 'none'",
402→                    ),
403→                );
404→            }
405→
406→            response
407→        },
408→        #[cfg(not(feature = "embedded-assets"))]
409→        None => {
410→            // When embedded-assets is disabled and no external dir is available,
411→            // provide a helpful error message.
412→            if matches!(&ASSET_STATE.source, AssetSource::Unavailable) {
413→                (
414→                    StatusCode::SERVICE_UNAVAILABLE,
415→                    "Web assets are not available. Install assets to /usr/share/moltis/web/ \
416→                     or set MOLTIS_SHARE_DIR to the directory containing them.",
417→                )
418→                    .into_response()
419→            } else {
420→                (StatusCode::NOT_FOUND, "not found").into_response()
421→            }
422→        },
423→        #[cfg(feature = "embedded-assets")]
424→        None => (StatusCode::NOT_FOUND, "not found").into_response(),
425→    }
426→}
