  9→//!   1. `read_skill` is present in the registry's tool list.
 10→//!   2. `{ name: "test-skill" }` returns the seeded body and lists sidecars.
 11→//!   3. `{ name: "test-skill", file_path: "references/notes.md" }` returns
 12→//!      the sidecar content.
 13→//!   4. An unknown skill name returns a friendly error.
 14→//!   5. A path-traversal `file_path` is rejected.
 15→//!
 16→//! This is the test that would have caught the original bug where the model
 17→//! silently fell back to a filesystem MCP server (or fabricated a body) when
 18→//! no native read tool was registered.
 19→
 20→#![allow(clippy::unwrap_used, clippy::expect_used)]
 21→
 22→use std::{path::Path, sync::Arc};
 23→
 24→use {
 25→    moltis_agents::tool_registry::{AgentTool, ToolRegistry},
 26→    moltis_skills::{
 27→        discover::{FsSkillDiscoverer, SkillDiscoverer},
 28→        types::SkillSource,
 29→    },
 30→    serde_json::json,
 31→    tempfile::TempDir,
 32→};
 33→
 34→/// Seed a personal-source skill at `<data_dir>/skills/<name>` with a known
 35→/// SKILL.md body, and create a `references/notes.md` sidecar. Returns the
 36→/// `(data_dir guard, skill_dir_path)` pair.
 37→fn seed_test_skill(name: &str, body: &str) -> (TempDir, std::path::PathBuf) {
 38→    let tmp = tempfile::tempdir().unwrap();
 39→    let skill_dir = tmp.path().join("skills").join(name);
 40→    std::fs::create_dir_all(&skill_dir).unwrap();
 41→    std::fs::write(
 42→        skill_dir.join("SKILL.md"),
 43→        format!("---\nname: {name}\ndescription: an integration-test skill\n---\n{body}"),
 44→    )
 45→    .unwrap();
 46→    std::fs::create_dir_all(skill_dir.join("references")).unwrap();
 47→    std::fs::write(
 48→        skill_dir.join("references/notes.md"),
 49→        "# Notes\n\nSome reference material.\n",
 50→    )
 51→    .unwrap();
 52→    (tmp, skill_dir)
 53→}
 54→
 55→/// Hermetic discoverer that only sees `<data_dir>/skills` as a Personal
 56→/// source — avoids hitting the user's real `~/.moltis` during tests.
 57→fn hermetic_discoverer(data_dir: &Path) -> Arc<dyn SkillDiscoverer> {
 58→    Arc::new(FsSkillDiscoverer::new(vec![(
 59→        data_dir.join("skills"),
 60→        SkillSource::Personal,
 61→    )]))
 62→}
 63→
 64→/// Build a `ToolRegistry` populated the same way `server.rs` does for
 65→/// skill-management tools, but scoped to a single temporary data directory.
 66→fn registry_for(data_dir: &Path) -> ToolRegistry {
 67→    let mut registry = ToolRegistry::new();
 68→
 69→    // Mirror the gateway's skill tool registration block from `server.rs`.
 70→    registry.register(Box::new(moltis_tools::skill_tools::CreateSkillTool::new(
 71→        data_dir.to_path_buf(),
 72→    )));
 73→    registry.register(Box::new(moltis_tools::skill_tools::UpdateSkillTool::new(
 74→        data_dir.to_path_buf(),
 75→    )));
 76→    registry.register(Box::new(moltis_tools::skill_tools::DeleteSkillTool::new(
 77→        data_dir.to_path_buf(),
 78→    )));
 79→    // `WriteSkillFilesTool` is gated behind `config.skills.enable_agent_sidecar_files`
 80→    // in production; the integration suite always registers it so we can
 81→    // exercise the write-then-read round trip.
 82→    registry.register(Box::new(
 83→        moltis_tools::skill_tools::WriteSkillFilesTool::new(data_dir.to_path_buf()),
 84→    ));
 85→
 86→    // `ReadSkillTool` uses a discoverer pointed at the same personal-skills
 87→    // directory the other tools write to. This intentionally does not include
 88→    // the global default paths — the test must be hermetic.
 89→    registry.register(Box::new(moltis_tools::skill_tools::ReadSkillTool::new(
 90→        hermetic_discoverer(data_dir),
 91→    )));
 92→
 93→    registry
 94→}
