294→// ── Parity invariants ──────────────────────────────────────────────────────
295→//
296→// The following tests verify the *cross-file* invariants that, if silently
297→// broken by a future refactor, would reintroduce the original fabrication
298→// bug. Every test in this section should be treated as a trip-wire: if it
299→// starts failing, the immediate question is "did we just regress skills?".
300→
301→/// The tool registered under the name `read_skill` must match the tool name
302→/// the prompt generator advertises. If someone renames the tool or the
303→/// prompt instruction without updating the other side, the model will never
304→/// find the tool the prompt tells it to use — reproducing the original bug.
305→#[tokio::test]
306→async fn read_skill_tool_name_matches_prompt_instruction() {
307→    let (tmp, _skill_dir) = seed_test_skill("test-skill", "# Test\n");
308→    let registry = registry_for(tmp.path());
309→
310→    // 1. The registered tool's `name()` must equal the shared constant
311→    //    the prompt generator references.
312→    let tool = registry
313→        .get(moltis_skills::prompt_gen::READ_SKILL_TOOL_NAME)
314→        .expect("tool name in prompt must resolve in the registry");
315→    assert_eq!(tool.name(), moltis_skills::prompt_gen::READ_SKILL_TOOL_NAME);
316→
317→    // 2. Generating a prompt must mention the exact tool name.
318→    let skills = vec![moltis_skills::types::SkillMetadata {
319→        name: "test-skill".into(),
320→        description: "an integration-test skill".into(),
321→        path: tmp.path().join("skills/test-skill"),
322→        source: Some(SkillSource::Personal),
323→        ..Default::default()
324→    }];
325→    let prompt = moltis_skills::prompt_gen::generate_skills_prompt(&skills);
326→    assert!(
327→        prompt.contains(moltis_skills::prompt_gen::READ_SKILL_TOOL_NAME),
328→        "activation instruction must name `read_skill`: {prompt}"
329→    );
330→
331→    // 3. The registered tool's schema must accept the shape the prompt
332→    //    advertises — `{ "name": "..." }` is all the primary call needs.
333→    let schema = tool.parameters_schema();
334→    assert_eq!(schema["type"], "object");
335→    let required: Vec<&str> = schema["required"]
336→        .as_array()
337→        .unwrap()
338→        .iter()
339→        .map(|v| v.as_str().unwrap())
340→        .collect();
341→    assert!(
342→        required.contains(&"name"),
343→        "primary read must require `name`: {schema}"
344→    );
345→    assert!(
346→        schema["properties"]["file_path"].is_object(),
347→        "sidecar read must accept optional `file_path`: {schema}"
348→    );
349→}
350→
351→/// Every skill name the prompt advertises must resolve through the tool.
352→/// This is the parity invariant the whole PR is built on — the prompt and
353→/// the tool share a discoverer, so what the model sees listed is what the
354→/// model can actually load. Without this test, a future refactor that
355→/// accidentally pointed them at different discoverers would silently break
356→/// skills again.
357→#[tokio::test]
358→async fn read_skill_resolves_every_name_listed_in_prompt() {
359→    let tmp = tempfile::tempdir().unwrap();
360→
361→    // Seed three distinct skills so the prompt has more than one entry
362→    // to parse. Each lives in the hermetic `<data_dir>/skills/` tree the
363→    // discoverer was configured to walk.
364→    for (name, body) in [
365→        ("alpha", "# Alpha body\n"),
366→        ("beta", "# Beta body\n"),
367→        ("gamma", "# Gamma body\n"),
368→    ] {
369→        let skill_dir = tmp.path().join("skills").join(name);
370→        std::fs::create_dir_all(&skill_dir).unwrap();
371→        std::fs::write(
372→            skill_dir.join("SKILL.md"),
373→            format!("---\nname: {name}\ndescription: test {name}\n---\n{body}"),
374→        )
375→        .unwrap();
376→    }
377→
378→    // Share ONE discoverer between the prompt builder and the tool —
379→    // this is the parity invariant in production too.
380→    let discoverer = hermetic_discoverer(tmp.path());
381→
382→    // Build the prompt from the discoverer's snapshot.
383→    let skills = discoverer.discover().await.unwrap();
384→    let prompt = moltis_skills::prompt_gen::generate_skills_prompt(&skills);
385→
386→    // Extract every `name="..."` token from the prompt. The prompt is
387→    // generated by our own code, so a naïve substring scan is fine.
388→    let mut listed_names = Vec::new();
389→    let mut rest = prompt.as_str();
390→    while let Some(idx) = rest.find("<skill name=\"") {
391→        rest = &rest[idx + "<skill name=\"".len()..];
392→        if let Some(end) = rest.find('"') {
393→            listed_names.push(rest[..end].to_string());
394→            rest = &rest[end..];
395→        }
396→    }
397→    assert_eq!(
398→        listed_names.len(),
399→        3,
400→        "prompt should list all three seeded skills, got {listed_names:?}"
401→    );
402→
403→    // For each name the prompt lists, the tool must resolve it — no
404→    // fabrication, no MCP fallback, just the discoverer's view.
405→    let tool = moltis_tools::skill_tools::ReadSkillTool::new(discoverer);
406→    for name in &listed_names {
407→        let result = tool
408→            .execute(json!({ "name": name }))
409→            .await
410→            .unwrap_or_else(|e| panic!("name '{name}' listed in prompt must resolve: {e}"));
411→        assert_eq!(result["name"], name.as_str());
412→        assert!(
413→            result["body"]
414→                .as_str()
415→                .unwrap()
416→                .contains(&format!("{} body", capitalize(name))),
417→            "body for '{name}' must match seeded content: {result}"
418→        );
419→    }
420→}
421→
422→fn capitalize(s: &str) -> String {
423→    let mut chars = s.chars();
424→    match chars.next() {
425→        Some(c) => c.to_uppercase().chain(chars).collect(),
426→        None => String::new(),
427→    }
428→}
