430→// ── Round-trip: write side → read side ────────────────────────────────────
431→//
432→// These tests prove that the create/update/write_files tools and the read
433→// tool agree on the on-disk layout. If someone changes the skills directory
434→// path in one place but not the other, these round-trips break immediately.
435→
436→/// Use `create_skill` to write a new personal skill, then `read_skill` to
437→/// load it back. The two tools must share the same `<data_dir>/skills/<name>`
438→/// layout — if they ever disagree, the agent can write a skill it can never
439→/// read back, which is its own silent-failure mode.
440→#[tokio::test]
441→async fn create_skill_then_read_skill_round_trip() {
442→    let tmp = tempfile::tempdir().unwrap();
443→    let registry = registry_for(tmp.path());
444→
445→    let create = registry
446→        .get("create_skill")
447→        .expect("create_skill is registered");
448→    create
449→        .execute(json!({
450→            "name": "round-trip",
451→            "description": "created via CreateSkillTool",
452→            "body": "# Round-trip body\n\nHello from create_skill.\n"
453→        }))
454→        .await
455→        .expect("create must succeed");
456→
457→    let read = registry
458→        .get("read_skill")
459→        .expect("read_skill is registered");
460→    let result = read
461→        .execute(json!({ "name": "round-trip" }))
462→        .await
463→        .expect("read must succeed for a just-created skill");
464→    assert_eq!(result["name"], "round-trip");
465→    assert_eq!(result["description"], "created via CreateSkillTool");
466→    assert!(
467→        result["body"].as_str().unwrap().contains("Round-trip body"),
468→        "body must reflect create_skill output: {result}"
469→    );
470→    assert_eq!(result["source"], "personal");
471→}
