492→    registry
493→        .get("write_skill_files")
494→        .unwrap()
495→        .execute(json!({
496→            "name": "with-sidecars",
497→            "files": [
498→                { "path": "references/api.md", "content": "# API notes\n" },
499→                { "path": "templates/prompt.txt", "content": "hello\n" },
500→                { "path": "assets/config.yaml", "content": "k: v\n" }
501→            ]
502→        }))
503→        .await
504→        .expect("write_skill_files must succeed");
505→
506→    // Primary read should list all three sidecars.
