540→/// Update → read round-trip: after `update_skill` replaces the body, the
541→/// next `read_skill` call must reflect the new content. Because the
542→/// discoverer re-runs on every `execute()`, this works without any
543→/// explicit cache invalidation.
544→#[tokio::test]
545→async fn update_skill_then_read_skill_reflects_new_body() {
546→    let tmp = tempfile::tempdir().unwrap();
547→    let registry = registry_for(tmp.path());
548→
549→    registry
550→        .get("create_skill")
551→        .unwrap()
552→        .execute(json!({
553→            "name": "mutable",
554→            "description": "v1",
555→            "body": "# Version 1\n"
556→        }))
557→        .await
558→        .unwrap();
559→
560→    let read = registry.get("read_skill").unwrap();
561→    let before = read.execute(json!({ "name": "mutable" })).await.unwrap();
562→    assert!(before["body"].as_str().unwrap().contains("Version 1"));
563→    assert_eq!(before["description"], "v1");
564→
565→    registry
566→        .get("update_skill")
567→        .unwrap()
568→        .execute(json!({
569→            "name": "mutable",
570→            "description": "v2",
571→            "body": "# Version 2\n"
