            .collect();

        let mut repos = repos;
        if let Ok(entries) = std::fs::read_dir(&install_dir) {
            for entry in entries.flatten() {
                let path = entry.path();
                if !path.is_dir() {
                    continue;
                }
                let repo_name = entry.file_name().to_string_lossy().to_string();
                if manifest.repos.iter().any(|r| r.repo_name == repo_name) {
