    async fn repos_unquarantine(&self, params: Value) -> ServiceResult {
        let source = params
            .get("source")
            .and_then(|v| v.as_str())
            .ok_or_else(|| "missing 'source' parameter".to_string())?;

        let manifest_path = moltis_skills::manifest::ManifestStore::default_path()
