        security_audit(
            "skills.repos.export",
            serde_json::json!({
                "source": source,
                "path": exported.bundle_path,
            }),
        );

        Ok(serde_json::json!({
            "source": exported.repo.source,
            "repo_name": exported.repo.repo_name,
            "path": exported.bundle_path,
        }))
    }

    async fn repos_import(&self, params: Value) -> ServiceResult {
